window.STUDY_DATA={"course": "CIS 4930", "title": "Final Exam Study Hub", "chapters": [{"id": "1", "title": "Git and GitHub", "full_title": "Version Control with Git and GitHub", "icon": "git", "sections": [{"title": "1.1 Repository states and the staging area", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Working directory", "The files currently present on disk, including edits that may not be staged."], ["Staging area / index", "The exact snapshot Git will use for the next commit."], ["Repository history", "Completed commits stored in the repository."], ["Tracked file", "A file Git already knows about through the index or history."], ["Untracked file", "A new file that has never been added to Git."], ["Modified file", "A tracked file whose working-directory contents changed."], ["Staged file", "A change copied into the index for the next commit."], ["Ignored file", "An untracked path matching an ignore rule and normally hidden from ordinary status output."]]}, {"type": "callout", "title": "Important commit-option distinction", "body": [{"type": "paragraph", "text": "git commit -a automatically stages modified and deleted tracked files, but it does not include a brand-new untracked file. A new file must first be staged with git add."}]}]}, {"title": "Final Exam Priorities and Class Hints", "blocks": [{"type": "callout", "title": "Professor emphasis", "body": [{"type": "paragraph", "text": "The final-exam announcement is the contract: every listed topic is fair game, including material that went beyond the original class notes."}, {"type": "paragraph", "text": "Professor warnings are high-value exam clues. Treat each WATCH OUT distinction like a likely short-answer question."}]}, {"type": "table", "rows": [["Class hint", "What to remember"], ["AWS console search bar", "Use it to quickly navigate to EC2, S3, IAM, or VPC."], ["jenkins/jenkins:lts", "lts means Long-Term Support: the stable maintained Jenkins image tag."], ["Built-in node executors", "Production best practice is 0 so builds do not run on the controller."], ["Jenkins definition", "Jenkins organizes when commands run, where they run, and how results are recorded."], ["Terraform lifecycle", "Write → init → fmt → validate → plan → apply → output → destroy."]]}, {"type": "callout", "title": "Topics flagged as newer or beyond class", "body": [{"type": "bullet", "text": "Git configuration scopes and git check-ignore."}, {"type": "bullet", "text": "Docker networking, CMD versus ENTRYPOINT, and build-cache behavior."}, {"type": "bullet", "text": "S3 versioning and delete markers."}, {"type": "bullet", "text": "Linux here-documents and redirection-order traps."}, {"type": "bullet", "text": "Terraform data blocks, fmt, output, for_each addresses, saved plans, and replacement."}, {"type": "bullet", "text": "Jenkins Declarative Pipeline syntax and post-run cleanup."}]}]}, {"title": "1.2 Examining changes", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["git status", "Shows the overall state of the current branch, staging area, working tree, and untracked files."], ["git diff", "Shows unstaged changes: working directory compared with the staging area."], ["git diff --staged", "Shows staged changes: staging area compared with the most recent commit. --cached is a synonym."], ["git status --ignored", "Displays ignored files in addition to normal status information."], ["git check-ignore -v path", "Verifies that a path matches an ignore rule and shows the rule and file that supplied it."], ["git show COMMIT", "Shows a commit's metadata and patch."], ["git show --stat COMMIT", "Shows the files and summary statistics included in a commit."]]}, {"type": "callout", "title": "Working tree versus staging area", "body": [{"type": "paragraph", "text": "Use git diff when the change is not yet staged. Use git diff --staged when the change has already been selected for the next commit."}]}]}, {"title": "1.8 Git Diff Details and History Comparisons", "blocks": [{"type": "table", "rows": [["Concept", "Meaning"], ["HEAD~1", "One commit before HEAD."], ["git diff HEAD~1 HEAD", "Compare the previous commit with the current commit."], ["git log --stat", "Show commit history with file-change statistics."], ["git diff hash1 hash2", "Compare any two commits."], ["Hunk header", "@@ -start,count +start,count @@; old-file range first, new-file range second."]]}, {"type": "callout", "title": "Reading a hunk header", "body": [{"type": "paragraph", "text": "In @@ -12,3 +12,5 @@, the old file begins at line 12 and spans 3 lines; the new file begins at line 12 and spans 5 lines."}, {"type": "paragraph", "text": "When the count is omitted, the count is 1."}]}, {"type": "exam_answer", "text": "Exam-ready answer: Choose the command based on whether you are comparing the working directory, staging area, or repository history."}]}, {"title": "1.3 Staging and committing", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["git add file", "Stage the current contents of one file."], ["git add .", "Stage current changes under the current directory, including new, modified, and deleted paths."], ["git add -A", "Stage changes across the entire working tree."], ["git commit -m \"message\"", "Create a commit from the staged snapshot."], ["git commit -a -m \"message\"", "Automatically stage tracked modifications/deletions, then commit; untracked files are excluded."], ["git restore --staged file", "Unstage a change without discarding the working-directory edit."]]}, {"type": "paragraph", "text": "Purpose of a commit: A commit permanently records the staged project snapshot in repository history with metadata such as author, time, parent commit, and message."}]}, {"title": "1.4 Branching and merging", "blocks": [{"type": "bullet", "text": "A branch is a movable name pointing to a commit and represents a line of development."}, {"type": "bullet", "text": "A merge combines another branch into the branch that is currently checked out."}, {"type": "bullet", "text": "The branch named in git merge is the source branch. The checked-out branch is the destination."}, {"type": "bullet", "text": "A fast-forward merge moves the current branch pointer forward when the current branch has no unique commits after the common ancestor."}, {"type": "bullet", "text": "When both branches contain unique commits, Git may create a merge commit with two parents."}, {"type": "bullet", "text": "A conflict occurs when Git cannot automatically combine competing changes."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["git branch feature-login", "Create a branch without switching to it."], ["git branch", "List local branches and mark the current branch."], ["git switch feature-login", "Switch to an existing branch."], ["git switch -c feature-login", "Create and switch to a new branch."], ["git checkout feature-login", "Older command that can switch branches."], ["git merge feature-login", "Merge feature-login into the currently checked-out branch."], ["git status", "During a conflict, shows unmerged paths and required next steps."], ["git add resolved-file", "Mark the edited conflict resolution as staged."], ["git commit", "Complete the merge after all conflicts are resolved and staged."], ["git merge --abort", "Cancel the unfinished merge and return to the pre-merge state when possible."]]}, {"type": "paragraph", "text": "Example: merge feature-login into main"}, {"type": "codeblock", "language": "Shell", "text": "git switch main\ngit merge feature-login"}]}, {"title": "1.5 Git configuration scopes", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["System", "Applies broadly to users and repositories on the computer."], ["Global", "Applies to the current user's repositories unless overridden."], ["Local repository", "Stored inside one repository and overrides broader settings for that repository."], ["git config --system --list", "Display system-scope settings."], ["git config --global --list", "Display global settings."], ["git config --local --list", "Display repository-local settings."], ["git config --list --show-origin", "Show effective settings and the configuration file that supplied each value."], ["git config user.name", "Show the effective commit author name."], ["git config user.email", "Show the effective commit author email."]]}, {"type": "callout", "title": "Repository-specific identity", "body": [{"type": "paragraph", "text": "A local user.name or user.email can override the global value for one repository without changing your identity in other repositories. Git stores identity information inside each commit."}]}]}, {"title": "1.6 Ignored files", "blocks": [{"type": "bullet", "text": "Ignore rules normally affect untracked files."}, {"type": "bullet", "text": "Adding a tracked file to .gitignore does not automatically remove it from Git tracking."}, {"type": "bullet", "text": "Common ignored paths include credentials, local environments, logs, dependency caches, and generated build files."}, {"type": "bullet", "text": ".gitignore is a repository-hygiene tool, not a security system. A secret already committed can remain in history."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], [".gitignore", "Repository file containing ignore patterns."], ["git status --ignored", "Show ignored paths while checking repository status."], ["git check-ignore -v file", "Verify which rule ignores a path."], ["git rm --cached file", "Stop tracking the file while keeping the local copy."], ["git rm -r --cached directory/", "Stop tracking a directory tree while keeping local copies."], ["git ls-files", "List files currently tracked by Git."]]}]}, {"title": "1.9 Gitignore Pattern Behavior", "blocks": [{"type": "bullet", "text": "* matches any number of characters."}, {"type": "bullet", "text": "? matches one character."}, {"type": "bullet", "text": "Rules are processed top to bottom; the last matching rule wins."}, {"type": "bullet", "text": "git add . normally skips matching untracked files."}, {"type": "bullet", "text": "Common ignored paths include .env, credentials, venv/, node_modules/, logs, build output, and generated files."}, {"type": "callout", "title": "Security warning", "body": [{"type": "paragraph", "text": "A secret already committed may still exist in repository history. Removing it from current files is not enough; rotate the secret."}]}, {"type": "codeblock", "language": "Shell", "text": "git check-ignore -v path/to/file\ngit status --ignored\ngit rm --cached path/to/file\ngit ls-files"}]}, {"title": "1.7 Common exam traps", "blocks": [{"type": "bullet", "text": "git diff and git diff --staged inspect different states."}, {"type": "bullet", "text": "A commit records the staged snapshot, not every file currently on disk."}, {"type": "bullet", "text": "git commit -a does not include new untracked files."}, {"type": "bullet", "text": "The current branch is the merge destination."}, {"type": "bullet", "text": ".gitignore does not automatically untrack an existing file."}, {"type": "bullet", "text": "Local configuration overrides global and system settings for one repository."}]}], "lead": "repository states, inspecting changes, commits, branches and merges, configuration scopes, and ignored files."}, {"id": "2", "title": "Docker", "full_title": "Docker", "icon": "docker", "sections": [{"title": "2.1 Images, containers, and runtime state", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Dockerfile", "Text instructions used to build an image."], ["Image", "Read-only packaged filesystem and startup metadata used as a container template."], ["Container", "A runnable instance of an image with its own process and runtime state."], ["Image layer", "A reusable filesystem/build result created by an image-building instruction."], ["Writable layer", "Container-specific top layer that stores runtime filesystem changes."], ["Registry", "A service that stores and distributes images, such as Docker Hub."]]}, {"type": "bullet", "text": "One image can create multiple independent containers."}, {"type": "bullet", "text": "A file changed inside one container normally belongs only to that container's writable layer."}, {"type": "bullet", "text": "Changing one container does not modify the original image or automatically update another container."}, {"type": "bullet", "text": "Removing the container normally removes its writable layer."}]}, {"title": "2.8 Docker Layer and Lifecycle Details", "blocks": [{"type": "bullet", "text": "Unchanged files are read from image layers."}, {"type": "bullet", "text": "When a container edits an image file, Docker copies the changed version into the writable layer."}, {"type": "bullet", "text": "Deleting an image-provided file creates a whiteout marker that hides the original; it does not alter the image."}, {"type": "bullet", "text": "docker stop preserves the container and its writable layer."}, {"type": "bullet", "text": "docker rm permanently removes the container and its writable layer."}, {"type": "table", "rows": [["Action", "Writable-layer result"], ["docker stop", "Preserved; the container can be started again."], ["docker start", "Reuses the existing writable layer."], ["docker rm", "Writable layer is destroyed."], ["New container from the same image", "Gets a separate writable layer."]]}]}, {"title": "2.2 Persistent storage", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Container-local writable layer", "Tied to one container and normally removed with it; unsuitable for important persistent data."], ["Named volume", "Docker chooses and manages the host storage location. Commonly used for database and application data."], ["Bind mount", "The user chooses an exact host path and mounts it into the container. Commonly used for source code and configuration."]]}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["docker volume create dbdata", "Create a named volume."], ["docker run --mount type=volume,src=dbdata,dst=/var/lib/data IMAGE", "Mount Docker-managed persistent storage."], ["docker run --mount type=bind,src=$PWD,dst=/app IMAGE", "Mount the current host directory into /app."], ["docker volume ls", "List Docker-managed volumes."]]}, {"type": "callout", "title": "Named volume versus bind mount", "body": [{"type": "paragraph", "text": "Named volumes are more portable because Docker manages the location. Bind mounts are tied to a specific host path but are convenient when the host must directly edit or inspect the files."}]}]}, {"title": "2.9 Mount Syntax and Selection Rules", "blocks": [{"type": "codeblock", "language": "Shell", "text": "docker volume create demo-vol\n\ndocker run --mount source=demo-vol,destination=/data ubuntu:22.04\n\ndocker run -v /home/me/app:/app node:20\n\ndocker run -v /var/run/docker.sock:/var/run/docker.sock jenkins/jenkins:lts"}, {"type": "bullet", "text": "With --mount, a volume is assumed unless type is specified."}, {"type": "bullet", "text": "With -v, a leading / in the source normally indicates a bind mount."}, {"type": "bullet", "text": "With -v, a bare source name normally indicates a named volume."}, {"type": "table", "rows": [["Need", "Best choice", "Reason"], ["Live source editing", "Bind mount", "Host edits appear immediately in the container."], ["Database data", "Named volume", "Portable Docker-managed persistence."], ["Temporary disposable files", "Writable layer", "No persistence requirement."], ["Docker socket access", "Bind mount", "Maps the exact host socket path."]]}]}, {"title": "2.3 Container networking", "blocks": [{"type": "bullet", "text": "Container IP addresses may change when containers are recreated and should not normally be hard-coded."}, {"type": "bullet", "text": "A user-defined Docker network isolates its members from unrelated networks."}, {"type": "bullet", "text": "Containers on the same user-defined network can normally reach one another by container name."}, {"type": "bullet", "text": "Docker Compose services can normally reach one another by service name on the Compose network."}, {"type": "bullet", "text": "Internal container-to-container communication is different from publishing a port to the host."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["docker network create appnet", "Create a user-defined network."], ["docker run --network appnet --name db IMAGE", "Attach a container named db to the network."], ["docker run --network appnet --name api IMAGE", "The api container can use db as the destination name."], ["-p 8080:80", "Publish host port 8080 and forward it to container port 80."], ["docker network inspect appnet", "Inspect network configuration and connected containers."]]}, {"type": "callout", "title": "Internal name versus published port", "body": [{"type": "paragraph", "text": "A container may contact another service by its Docker/Compose name without publishing that service to the host. Publishing a port is required when a client outside the Docker network must enter through the host."}]}]}, {"title": "2.4 Dockerfile build behavior and cache reuse", "blocks": [{"type": "bullet", "text": "The build context is the set of files available to the Docker build."}, {"type": "bullet", "text": ".dockerignore removes unnecessary or sensitive paths from the build context."}, {"type": "bullet", "text": "Each Dockerfile instruction normally produces or reuses a cached layer."}, {"type": "bullet", "text": "A change to an instruction, its inputs, or an earlier layer invalidates that layer and later layers."}, {"type": "bullet", "text": "Stable, expensive dependency installation should appear before frequently changing application source."}, {"type": "bullet", "text": "The pattern applies to Python requirements files, Node package lock files, Java build files, Go modules, and other dependency descriptors."}, {"type": "callout", "title": "Cache-friendly pattern", "body": [{"type": "codeblock", "language": "Dockerfile", "text": "FROM python:3.12-slim\n\nWORKDIR /app\n\nCOPY requirements.txt .\nRUN pip install --no-cache-dir -r requirements.txt\n\nCOPY . .\n\nCMD [\"python\", \"app.py\"]"}]}, {"type": "callout", "title": "Why source changes should not reinstall dependencies", "body": [{"type": "paragraph", "text": "When requirements.txt is unchanged, Docker can reuse the dependency-install layer. Copying the entire source tree before the installation step would cause ordinary source edits to invalidate that expensive layer."}]}]}, {"title": "2.10 Docker Build Context and Multi-Ecosystem Cache Pattern", "blocks": [{"type": "bullet", "text": "The final dot in docker build -t name . is the build context."}, {"type": "bullet", "text": "COPY and ADD can access only files inside the build context."}, {"type": "bullet", "text": ".dockerignore reduces upload size and prevents irrelevant changes from invalidating cache."}, {"type": "table", "rows": [["Ecosystem", "Cache-friendly order"], ["Python", "COPY requirements.txt → RUN pip install → COPY source"], ["Node", "COPY package.json and lock file → RUN npm ci → COPY source"], ["Java/Maven", "COPY pom.xml → resolve dependencies → COPY source"], ["Go", "COPY go.mod/go.sum → download modules → COPY source"]]}, {"type": "callout", "title": "What invalidates a cached layer", "body": [{"type": "paragraph", "text": "Changing the instruction, changing a file used by COPY/ADD, or invalidating any earlier layer."}]}]}, {"title": "2.5 Container startup commands", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["CMD", "Sets a default command or default arguments. A command after the image name commonly replaces CMD."], ["ENTRYPOINT", "Sets the primary executable. Runtime arguments are commonly appended to an exec-form ENTRYPOINT."], ["docker run IMAGE command", "Supplies a runtime command after the image name; normally replaces CMD or becomes ENTRYPOINT arguments."], ["--entrypoint executable", "Replaces the image's configured ENTRYPOINT."], ["-i", "Keeps standard input open."], ["-t", "Allocates a pseudo-terminal. Often combined as -it."], ["sh / bash", "A shell must actually exist in the image. Minimal images may not include bash or any interactive shell."]]}, {"type": "callout", "title": "CMD and ENTRYPOINT interaction", "body": [{"type": "codeblock", "language": "Dockerfile + Shell", "text": "# Image configuration\nENTRYPOINT [\"python\", \"tool.py\"]\nCMD [\"--serve\"]\n\n# Uses the default CMD argument\ndocker run mytool\n\n# Replaces CMD with --check\ndocker run mytool --check\n\n# Replaces ENTRYPOINT itself\ndocker run --entrypoint /bin/sh mytool"}]}]}, {"title": "2.6 Commands directly related to the practice questions", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["docker images", "Display images stored locally. docker image ls is the equivalent object-style command."], ["docker ps", "Display running containers."], ["docker ps -a", "Display running and stopped containers."], ["docker run -it IMAGE sh", "Start an interactive terminal when sh exists."], ["docker logs CONTAINER", "Display the container's output and errors."]]}]}, {"title": "2.11 Core Docker Commands and Class Notes", "blocks": [{"type": "codeblock", "language": "Shell", "text": "docker version\ndocker pull image:tag\ndocker images\ndocker ps\ndocker ps -a\ndocker stop CONTAINER\ndocker start CONTAINER\ndocker rm -f CONTAINER\ndocker rmi IMAGE\ndocker logs --tail 50 -f CONTAINER\ndocker inspect CONTAINER\ndocker inspect IMAGE\ndocker exec -it CONTAINER sh\ndocker build -t name ."}, {"type": "bullet", "text": "No image tag means :latest, which is not necessarily the most stable release."}, {"type": "bullet", "text": "docker inspect can reveal metadata such as exposed ports."}, {"type": "bullet", "text": "docker exec enters a running container; docker run creates a new one."}, {"type": "bullet", "text": "-f means follow in docker logs -f, but force in docker rm -f and docker rmi -f."}, {"type": "callout", "title": "Class hint: Jenkins LTS", "body": [{"type": "paragraph", "text": "jenkins/jenkins:lts uses the Long-Term Support release line."}]}]}, {"title": "2.7 Common exam traps", "blocks": [{"type": "bullet", "text": "A container is an instance of an image, not the same object."}, {"type": "bullet", "text": "The writable layer is not reliable persistent storage."}, {"type": "bullet", "text": "A container name or Compose service name is safer than a hard-coded container IP."}, {"type": "bullet", "text": "In -p HOST:CONTAINER, the left side is the host port."}, {"type": "bullet", "text": ".dockerignore limits the build context; it is separate from .gitignore."}, {"type": "bullet", "text": "A command after the image name does not necessarily replace ENTRYPOINT."}, {"type": "bullet", "text": "Minimal images may not contain bash."}]}], "lead": "images, containers, writable layers, persistent storage, networking, build cache, CMD, ENTRYPOINT, and runtime overrides."}, {"id": "3", "title": "AWS", "full_title": "AWS", "icon": "aws", "sections": [{"title": "3.1 Publishing a containerized application from EC2", "blocks": [{"type": "number", "text": "1. The user connects to the EC2 instance's public IPv4 address or public DNS name."}, {"type": "number", "text": "2. The VPC route table and internet gateway provide the public network path."}, {"type": "number", "text": "3. The security group permits the destination protocol and host port from the client's source CIDR."}, {"type": "number", "text": "4. The EC2 operating system accepts the traffic through its local firewall."}, {"type": "number", "text": "5. Docker receives traffic on the published host port and forwards it to the container port."}, {"type": "number", "text": "6. The application is running and listens on an address reachable through the container interface, commonly 0.0.0.0 instead of only 127.0.0.1."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Security-group inbound rule", "Allows a specific protocol and destination port from a source CIDR or security group."], ["Protocol and port range", "Must match the service, such as TCP 80, 443, 22, or 3389."], ["Source CIDR", "Defines which client addresses are allowed. x.x.x.x/32 represents one IPv4 address."], ["Public IPv4 / public DNS", "Provides an internet-reachable address when combined with correct routing."], ["Internet gateway", "Connects the VPC to the public internet."], ["Route table", "Directs destination traffic to a target, such as 0.0.0.0/0 to an internet gateway."], ["Host port", "The port exposed on the EC2 operating system."], ["Container port", "The internal port on which the containerized service listens."], ["OS firewall", "A separate security layer inside the instance."], ["Application listen address", "Determines which interfaces the process accepts connections on."]]}, {"type": "callout", "title": "Docker mapping is only one layer", "body": [{"type": "paragraph", "text": "A Docker -p mapping does not create an AWS security-group rule, route, public address, or operating-system firewall permission. Every layer must agree."}]}]}, {"title": "3.2 EC2 fundamentals and remote access", "blocks": [{"type": "bullet", "text": "EC2 stands for Elastic Compute Cloud and runs virtual server instances."}, {"type": "bullet", "text": "Instances can run Linux or Windows."}, {"type": "bullet", "text": "An instance must be running and reachable through the correct network path."}, {"type": "bullet", "text": "A public IP alone does not guarantee that the server is reachable."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Linux EC2", "Normally managed with SSH over TCP 22 using an SSH client, the correct image-specific user name, and a private key or other configured authentication."], ["Windows EC2", "Normally managed with RDP over TCP 3389 using a Remote Desktop client and Windows credentials."], ["Security group", "Must permit the correct management port from a suitably restricted source."]]}]}, {"title": "3.12 EC2 Key and File-Transfer Details", "blocks": [{"type": "bullet", "text": "A .pem private key is generally downloadable only once when the key pair is created."}, {"type": "bullet", "text": "Restrict SSH or RDP to your IP using a /32 source where practical."}, {"type": "codeblock", "language": "Shell", "text": "ssh -i key.pem ubuntu@PUBLIC_IP\n\nscp -i key.pem local-file.txt ubuntu@PUBLIC_IP:~"}, {"type": "exam_answer", "text": "Exam-ready answer: Linux remote access uses SSH on port 22; Windows uses RDP on port 3389."}]}, {"title": "3.3 VPCs, subnets, route tables, and internet gateways", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["VPC", "Virtual Private Cloud: the isolated logical AWS network that contains resources and network configuration."], ["Subnet", "A smaller IP range inside the VPC, associated with one Availability Zone."], ["Public subnet", "Has a route to an internet gateway and supports internet-facing resources with public addressing."], ["Private subnet", "Does not directly expose its instances to the internet through an internet gateway."], ["Route table", "Contains destination-and-target rules controlling where traffic goes."], ["0.0.0.0/0", "The IPv4 default route, matching destinations not covered by a more specific route."], ["Internet gateway", "A VPC component used for public internet connectivity."]]}]}, {"title": "3.4 Security groups", "blocks": [{"type": "bullet", "text": "A security group is a stateful virtual firewall attached to AWS resources such as EC2 network interfaces."}, {"type": "bullet", "text": "Inbound rules control permitted incoming traffic."}, {"type": "bullet", "text": "Outbound rules control permitted outgoing traffic."}, {"type": "bullet", "text": "A rule includes a protocol, port or port range, and source or destination."}, {"type": "bullet", "text": "Management ports should be restricted to trusted source addresses rather than opened broadly."}]}, {"title": "3.5 IAM", "blocks": [{"type": "paragraph", "text": "IAM stands for Identity and Access Management. It controls which identities can access AWS and which actions they can perform."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["IAM user", "An identity representing a person or application when a long-lived IAM identity is appropriate."], ["IAM group", "A collection of users used to assign permissions at scale."], ["IAM role", "An assumable identity that supplies temporary permissions, commonly used by AWS services and workloads."], ["IAM policy", "A JSON permission document that allows or denies actions on resources under specified conditions."], ["Least privilege", "Grant only the permissions required to complete the task."]]}]}, {"title": "3.6 S3 versioning and deletion", "blocks": [{"type": "bullet", "text": "A version-enabled bucket can preserve multiple versions of an object with the same key."}, {"type": "bullet", "text": "Each stored version has a version ID."}, {"type": "bullet", "text": "The current version is the version returned by ordinary access."}, {"type": "bullet", "text": "Older preserved versions are noncurrent versions."}, {"type": "bullet", "text": "Deleting without specifying a version ID normally creates a delete marker as the current version."}, {"type": "bullet", "text": "The object disappears from ordinary listings or requests because the delete marker is current, even though earlier versions may still exist."}, {"type": "bullet", "text": "A previous version can be restored by removing the current delete marker or copying an older version to create a new current version."}, {"type": "bullet", "text": "Permanently deleting a particular version requires selecting its version ID."}, {"type": "bullet", "text": "Versioning improves recovery from overwrites and deletions but is not the same as an independent backup strategy."}]}, {"title": "3.11 S3 Class Recap and Public Access Mechanics", "blocks": [{"type": "bullet", "text": "A bucket is the container; an object is the stored data item."}, {"type": "bullet", "text": "An S3 object can be up to 5 TB."}, {"type": "bullet", "text": "Bucket names must be unique within AWS's naming scope."}, {"type": "bullet", "text": "The bucket region is selected at creation."}, {"type": "callout", "title": "Public access requires multiple layers", "body": [{"type": "paragraph", "text": "Public access may require disabling the relevant Block Public Access settings and adding a bucket policy."}, {"type": "paragraph", "text": "A typical read policy uses Effect Allow, Principal *, Action s3:GetObject, and a Resource ending in bucket-arn/*."}]}, {"type": "codeblock", "language": "JSON", "text": "{\n  \"Effect\": \"Allow\",\n  \"Principal\": \"*\",\n  \"Action\": \"s3:GetObject\",\n  \"Resource\": \"arn:aws:s3:::example-bucket/*\"\n}"}]}, {"title": "3.7 AWS storage categories", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Amazon S3", "Object storage for independent objects addressed by bucket and key. Suitable for web content, logs, backups, and large-scale object access."], ["Amazon EBS", "Persistent block storage presented as a disk to EC2. Suitable for operating-system volumes and workloads needing a block device."], ["Amazon EFS", "Managed shared file storage that multiple instances can mount. Included because the practice question asks about a shared filesystem."], ["Instance store", "Temporary block storage physically attached to the host; not appropriate when data must survive the instance lifecycle."]]}, {"type": "callout", "title": "Storage practice question", "body": [{"type": "paragraph", "text": "Independent web-addressable files -> S3 object storage. A disk attached to one EC2 instance -> EBS block storage. A shared filesystem mounted by several instances -> EFS file storage."}]}]}, {"title": "3.8 Persistent EC2 storage and S3 protections", "blocks": [{"type": "bullet", "text": "EBS volumes can persist independently of an EC2 instance when configured not to be deleted with the instance."}, {"type": "bullet", "text": "S3 bucket policies, IAM policies, and object ownership settings control access."}, {"type": "bullet", "text": "S3 Block Public Access settings help prevent accidental public exposure."}, {"type": "bullet", "text": "Do not rely on public access when a private IAM-based design is appropriate."}, {"type": "bullet", "text": "Use least privilege for both identities and resource policies."}]}, {"title": "3.10 Broader AWS Review from Class", "blocks": [{"type": "table", "rows": [["Topic", "Class-covered detail"], ["EC2", "Instances launch from AMIs. t3.micro means family t, generation 3, size micro."], ["Console navigation", "Use the AWS search bar to jump to EC2, S3, IAM, and VPC."], ["Hierarchy", "Region → Availability Zone → subnet."], ["Region choice", "Choose based on customers, latency, services, compliance, and cost."], ["Availability Zones", "Use multiple AZs for redundancy."], ["Bastion pattern", "SSH to a public instance, then hop to a private instance by private IP."], ["Root account", "Protect with MFA; use limited IAM identities for daily work."]]}, {"type": "callout", "title": "Public versus private design", "body": [{"type": "paragraph", "text": "Public-facing resources need a public path. Databases and internal services are generally safer in private subnets."}]}]}, {"title": "3.9 Common exam traps", "blocks": [{"type": "bullet", "text": "A public IP does not guarantee reachability."}, {"type": "bullet", "text": "Security groups and operating-system firewalls are separate layers."}, {"type": "bullet", "text": "Host port and container port are not necessarily the same number."}, {"type": "bullet", "text": "SSH and RDP use different ports, clients, and credential methods."}, {"type": "bullet", "text": "An S3 delete marker can hide an object without erasing every version."}, {"type": "bullet", "text": "Versioning is not a complete backup strategy."}, {"type": "bullet", "text": "S3 is object storage, EBS is block storage, and EFS is shared file storage."}]}], "lead": "EC2 network reachability, remote access, S3 versioning, storage categories, VPCs, security groups, IAM, persistent storage, S3 protection, and least privilege."}, {"id": "4", "title": "Linux", "full_title": "Linux", "icon": "linux", "sections": [{"title": "4.1 Environment variables and command lookup", "blocks": [{"type": "bullet", "text": "An environment variable is a named value supplied to a process and normally inherited by child processes."}, {"type": "bullet", "text": "A shell variable is not automatically inherited unless it is exported."}, {"type": "bullet", "text": "The shell expands $NAME to the variable's value."}, {"type": "bullet", "text": "PATH is a colon-separated list of directories searched from left to right when a command name contains no slash."}, {"type": "bullet", "text": "Placing an unsafe writable directory early in PATH can cause the wrong executable to run."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["echo \"$HOME\"", "Display the value of one environment variable."], ["NAME=value", "Set a variable in the current shell."], ["export NAME=value", "Set and export a variable to subsequently started child processes."], ["NAME=value command", "Temporarily set a variable only for one command invocation."], ["echo \"$PATH\"", "Display the command-search path."], ["command -v python", "Show the command the shell would execute."], ["type cd", "Explain whether a name is a shell builtin, alias, function, or external command."], ["~/.bashrc", "A common Bash startup file used for interactive-shell aliases and exports."]]}]}, {"title": "4.2 Standard streams and redirection", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["0 - STDIN", "Standard Input: where a process receives input."], ["1 - STDOUT", "Standard Output: normal program output."], ["2 - STDERR", "Standard Error: diagnostic and error output."], ["> file", "Redirect STDOUT and overwrite the file."], [">> file", "Redirect STDOUT and append to the file."], ["2> file", "Redirect STDERR and overwrite the file."], ["2>> file", "Redirect STDERR and append to the file."], ["command > all.log 2>&1", "Send STDOUT to the file, then duplicate STDERR to the same destination."], ["command 2>&1 > output.log", "Duplicate STDERR to the original STDOUT destination, then redirect only STDOUT to the file."], ["command > out.log 2> err.log", "Keep normal output and errors in separate files."], ["|", "Pipe the left command's STDOUT into the right command's STDIN."], ["|&", "In Bash, pipe both STDOUT and STDERR."]]}, {"type": "callout", "title": "Redirection order matters", "body": [{"type": "paragraph", "text": "The shell processes redirections from left to right. 2>&1 copies the destination that STDOUT has at that moment, so changing the order can change where STDERR goes."}]}]}, {"title": "4.7 Additional Redirection Forms", "blocks": [{"type": "codeblock", "language": "Shell", "text": "command &> all.txt\ncommand 2>/dev/null\ncmd1 | cmd2\ncmd1 |& cmd2"}, {"type": "table", "rows": [["Syntax", "Meaning"], ["&> all.txt", "Bash shortcut sending STDOUT and STDERR to the same file."], ["2>/dev/null", "Discard STDERR."], ["|", "Pipe STDOUT only."], ["|&", "Pipe STDOUT and STDERR in Bash."]]}]}, {"title": "4.3 Here-documents", "blocks": [{"type": "paragraph", "text": "A here-document supplies a multiline block of text as standard input. The shell reads until it reaches the closing delimiter."}, {"type": "paragraph", "text": "Unquoted delimiter: variables may expand"}, {"type": "codeblock", "language": "Shell", "text": "cat > app.conf <<EOF\nport=$PORT\nmode=production\nEOF"}, {"type": "paragraph", "text": "Quoted delimiter: content remains literal"}, {"type": "codeblock", "language": "Shell", "text": "cat > literal.conf <<'EOF'\nport=$PORT\nmode=production\nEOF"}, {"type": "bullet", "text": "The word after << is the opening delimiter name."}, {"type": "bullet", "text": "The closing delimiter must be spelled exactly and normally appear alone at the beginning of a line."}, {"type": "bullet", "text": "The command can redirect the generated content into a file without an interactive editor."}, {"type": "bullet", "text": "Quoting the delimiter prevents normal shell expansion inside the body."}]}, {"title": "4.8 Here-Document Construction Rules", "blocks": [{"type": "codeblock", "language": "Shell", "text": "cat << MYEOF > config.txt\nserver=localhost\nport=8080\nuser=$USER\nMYEOF"}, {"type": "bullet", "text": "The closing delimiter must appear alone at the start of a line."}, {"type": "bullet", "text": "A misspelled or misplaced closing delimiter makes the shell continue reading."}, {"type": "bullet", "text": "An unquoted delimiter allows variable and command expansion."}, {"type": "bullet", "text": "A quoted delimiter keeps the content literal."}, {"type": "codeblock", "language": "Shell", "text": "cat << 'MYEOF' > literal.txt\nuser=$USER\nMYEOF"}, {"type": "exam_answer", "text": "Exam-ready answer: Use an unquoted delimiter when expansion is wanted and a quoted delimiter when literal text is required."}]}, {"title": "4.4 Symbolic links and path resolution", "blocks": [{"type": "bullet", "text": "A symbolic link stores a path that points to another file or directory."}, {"type": "bullet", "text": "A logical path is the path preserved from how the shell navigated."}, {"type": "bullet", "text": "A physical path is the actual filesystem destination after symbolic links are resolved."}, {"type": "bullet", "text": "Two different displayed paths can refer to the same physical directory."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["ln -s target link_name", "Create a symbolic link."], ["pwd", "Print the current working directory, normally using the shell's logical path."], ["pwd -L", "Explicitly display the logical path."], ["pwd -P", "Resolve symbolic links and display the physical path."], ["readlink link_name", "Display the stored target of a symbolic link."]]}, {"type": "callout", "title": "Why both paths are correct", "body": [{"type": "paragraph", "text": "If current points to releases/v4 and you enter through current, pwd -L can show the logical path containing current while pwd -P shows releases/v4. They are different names for the same physical destination."}]}]}, {"title": "4.9 Hard Links and Directory Link Counts", "blocks": [{"type": "bullet", "text": "Hard links are additional names for the same inode."}, {"type": "bullet", "text": "Hard links to directories are normally disallowed except for automatic . and .. entries."}, {"type": "bullet", "text": "An empty directory normally has link count 2."}, {"type": "bullet", "text": "Each immediate subdirectory adds one link to the parent through its .. entry."}, {"type": "table", "rows": [["Entry", "Meaning"], [".", "Current directory."], ["..", "Parent directory."], ["Symbolic link", "Stores a path to another location."], ["Hard link", "Another directory entry for the same inode."]]}]}, {"title": "4.5 Directory navigation", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["cd ~", "Go to the current user's home directory."], ["cd", "With no argument, normally also goes to the home directory."], ["cd ..", "Go to the parent directory."], ["cd /absolute/path", "Navigate using a path beginning at the filesystem root."], ["cd relative/path", "Navigate relative to the current working directory."], ["cd -", "Return to the previous working directory and normally print it."], ["pwd -L", "Display the logical current directory."], ["pwd -P", "Display the resolved physical directory."]]}]}, {"title": "4.6 Common exam traps", "blocks": [{"type": "bullet", "text": "Setting a shell variable and exporting it are not the same operation."}, {"type": "bullet", "text": "PATH is searched in order from left to right."}, {"type": "bullet", "text": "A pipe sends STDOUT unless STDERR is explicitly combined."}, {"type": "bullet", "text": "Redirection order changes the result because file-descriptor duplication is time-sensitive."}, {"type": "bullet", "text": "Quoted and unquoted here-document delimiters handle expansion differently."}, {"type": "bullet", "text": "pwd -L and pwd -P can show different strings for the same directory."}, {"type": "bullet", "text": "cd - means the previously visited directory, not the parent directory."}]}], "lead": "environment variables and command lookup, standard streams and redirection, here-documents, symbolic links, path resolution, and directory navigation."}, {"id": "5", "title": "Terraform", "full_title": "Terraform", "icon": "terraform", "sections": [{"title": "5.1 Core workflow and commands", "blocks": [{"type": "number", "text": "1. Write or edit Terraform configuration files."}, {"type": "number", "text": "2. Initialize the working directory."}, {"type": "number", "text": "3. Format the configuration."}, {"type": "number", "text": "4. Validate syntax and internal consistency."}, {"type": "number", "text": "5. Preview proposed changes."}, {"type": "number", "text": "6. Apply approved changes."}, {"type": "number", "text": "7. Inspect outputs and managed infrastructure information."}, {"type": "number", "text": "8. Destroy managed infrastructure when it is no longer needed."}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["terraform init", "Initialize the working directory and install required providers and modules."], ["terraform fmt", "Rewrite configuration using standard formatting. It does not change infrastructure."], ["terraform validate", "Check syntax and internal consistency. It does not deploy resources."], ["terraform plan", "Preview proposed infrastructure actions without applying them."], ["terraform apply", "Create a plan and, after approval, perform the changes."], ["terraform output", "Display values declared by output blocks."], ["terraform destroy", "Plan and remove the infrastructure managed through the current state/configuration."]]}]}, {"title": "5.12 Apply Approval and Auto-Approve", "blocks": [{"type": "bullet", "text": "terraform apply normally displays a plan and prompts for yes."}, {"type": "bullet", "text": "terraform destroy also prompts for confirmation."}, {"type": "codeblock", "language": "Shell", "text": "terraform apply -auto-approve\nterraform destroy -auto-approve"}, {"type": "callout", "title": "Safety warning", "body": [{"type": "paragraph", "text": "-auto-approve skips interactive confirmation. It is convenient in labs and automation but removes a safety checkpoint."}]}]}, {"title": "5.9 State, Lock Files, and Inspection Commands", "blocks": [{"type": "table", "rows": [["File / command", "Meaning"], [".terraform/", "Local working data and installed providers/modules."], [".terraform.lock.hcl", "Records exact selected provider versions and checksums."], ["terraform.tfstate", "Mapping of managed resources and known attributes."], ["terraform.tfstate.backup", "Previous state snapshot."], ["terraform state list", "List resource addresses in state."], ["terraform state show ADDRESS", "Inspect one resource in state."], ["terraform show", "Display state or a saved plan."]]}, {"type": "callout", "title": "State safety", "body": [{"type": "paragraph", "text": "Do not hand-edit state. Terraform uses it to compare configuration with managed infrastructure."}]}]}, {"title": "5.2 Configuration building blocks and project files", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Resource block", "Declares an infrastructure object Terraform manages."], ["Data block", "Reads information about an existing object without managing its creation."], ["Input variable", "Allows a value to be supplied to the configuration."], ["Local value", "A named expression used inside a module to avoid repetition."], ["Output block", "Exposes a selected result."], ["Variable-definition file", "Supplies values, commonly through terraform.tfvars or *.auto.tfvars."], ["Reference", "Uses another block's attribute, such as aws_instance.web.id."], [".terraform directory", "Stores working-directory data such as installed providers/modules and backend information; normally not committed."], [".terraform.lock.hcl", "Dependency lock file recording selected provider versions and checksums; normally committed."], [".tf", "Normal Terraform configuration-file extension."]]}, {"type": "callout", "title": "Basic HCL relationships", "body": [{"type": "codeblock", "language": "HCL", "text": "variable \"instance_type\" {\n  type    = string\n  default = \"t3.micro\"\n}\n\nresource \"aws_instance\" \"web\" {\n  instance_type = var.instance_type\n}\n\noutput \"instance_id\" {\n  value = aws_instance.web.id\n}"}]}]}, {"title": "5.10 Complete Terraform Block-Type Example", "blocks": [{"type": "codeblock", "language": "HCL", "text": "terraform {\n  required_providers {\n    docker = {\n      source  = \"kreuzwerker/docker\"\n      version = \"~> 3.0\"\n    }\n  }\n}\n\nprovider \"docker\" {}\n\nresource \"docker_image\" \"nginx\" {\n  name = \"nginx:latest\"\n}\n\ndata \"aws_ami\" \"ubuntu\" {\n  most_recent = true\n}\n\nvariable \"app_name\" {\n  type    = string\n  default = \"flask-app\"\n}\n\nlocals {\n  common_tags = {\n    project = \"demo\"\n  }\n}\n\noutput \"url\" {\n  value = \"http://localhost:${var.external_port}\"\n}"}, {"type": "table", "rows": [["Block", "Role"], ["terraform", "Terraform settings and required providers."], ["provider", "Configures access to a platform API."], ["resource", "Creates and manages an object."], ["data", "Reads existing information without managing creation."], ["variable", "Receives input."], ["locals", "Defines reusable local expressions."], ["output", "Exposes a result after apply."]]}, {"type": "bullet", "text": "terraform.tfvars supplies variable values."}, {"type": "bullet", "text": "Terraform merges every .tf file in the directory; filenames are organizational conventions."}, {"type": "bullet", "text": "References include var.app_name, local.common_tags.project, docker_image.nginx.image_id, and data.aws_ami.ubuntu.id."}, {"type": "bullet", "text": "String interpolation uses syntax such as \"${var.app_name}-dev\"."}]}, {"title": "5.3 Reading a Terraform plan", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["+", "Create a resource."], ["~", "Modify a resource in place."], ["-", "Destroy a resource."], ["-/+ or +/-", "Replace a resource by destroying and creating in the order shown."], ["known after apply", "The value cannot be calculated until the operation runs."], ["Plan: X to add, Y to change, Z to destroy", "Summary of proposed actions. Still inspect the attribute-level cause."]]}, {"type": "callout", "title": "In-place update versus replacement", "body": [{"type": "paragraph", "text": "An in-place update changes the existing managed object. A replacement creates a new object and destroys the old one, which may change identifiers, cause downtime, or temporarily create two objects."}]}]}, {"title": "5.4 Resource addresses", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["aws_instance.web", "Resource type aws_instance and local Terraform name web."], ["aws_instance.web.id", "The id attribute of that resource."], ["module.network.aws_subnet.public", "A resource inside the child module named network."], ["aws_instance.web[0]", "An indexed instance created with count."], ["aws_instance.web[\"blue\"]", "An instance selected by a for_each key."]]}, {"type": "callout", "title": "Local name versus external name", "body": [{"type": "paragraph", "text": "The Terraform local name web is used in configuration references. It does not have to match the resource's display name or identifier in AWS."}]}]}, {"title": "5.5 Resource dependencies", "blocks": [{"type": "bullet", "text": "Terraform builds a dependency graph to determine the correct operation order."}, {"type": "bullet", "text": "An implicit dependency is created when one block references another block's attribute."}, {"type": "bullet", "text": "depends_on creates an explicit dependency when a real ordering relationship exists but is not represented by a normal reference."}, {"type": "bullet", "text": "Unnecessary explicit dependencies reduce parallelism and can make more values unknown during planning."}, {"type": "bullet", "text": "The textual order of blocks in a .tf file does not control provisioning order."}, {"type": "callout", "title": "Implicit dependency through a reference", "body": [{"type": "codeblock", "language": "HCL", "text": "resource \"aws_instance\" \"web\" {\n  subnet_id = aws_subnet.public.id\n}"}]}]}, {"title": "5.6 Saved plans", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["terraform plan -out=tfplan", "Generate and save a specific plan artifact for review."], ["terraform apply tfplan", "Apply the saved artifact without generating a new plan."], ["terraform apply", "Without a saved file, Terraform generates a new plan during the apply process."]]}, {"type": "bullet", "text": "Saved plans improve predictability because the applied actions are the actions that were reviewed."}, {"type": "bullet", "text": "An older plan may become inappropriate if configuration, variables, provider selections, state, credentials, or real infrastructure change."}, {"type": "bullet", "text": "Recreate and review the plan when its assumptions are no longer current."}]}, {"title": "5.7 Providers", "blocks": [{"type": "bullet", "text": "A provider plugin connects Terraform to an external platform API."}, {"type": "bullet", "text": "A required_providers declaration identifies the provider source and version constraint."}, {"type": "bullet", "text": "A provider block supplies configuration such as region, endpoint, or an alias."}, {"type": "bullet", "text": "terraform init installs selected provider plugins."}, {"type": "bullet", "text": "Authentication should normally come from the provider's supported credential methods rather than hard-coded secrets."}, {"type": "bullet", "text": "A provider is the platform integration, a resource is a managed object, and a data source reads external information."}, {"type": "callout", "title": "Provider configuration example", "body": [{"type": "codeblock", "language": "HCL", "text": "terraform {\n  required_providers {\n    aws = {\n      source  = \"hashicorp/aws\"\n      version = \"~> 6.0\"\n    }\n  }\n}\n\nprovider \"aws\" {\n  region = \"us-east-1\"\n}"}]}]}, {"title": "5.11 Provider Versioning and Registry Documentation", "blocks": [{"type": "bullet", "text": "~> 3.0 allows compatible 3.x versions but excludes 4.0."}, {"type": "bullet", "text": "The lock file records the exact provider version selected."}, {"type": "bullet", "text": "Pinning reduces unexpected breakage from future releases."}, {"type": "bullet", "text": "The provider translates Terraform operations into platform API calls."}, {"type": "bullet", "text": "The Terraform Registry documents required arguments, optional arguments, and exported attributes."}, {"type": "callout", "title": "Provider versus Terraform core", "body": [{"type": "paragraph", "text": "Terraform core builds the plan and dependency graph. The provider performs platform-specific API operations."}]}]}, {"title": "5.8 Common exam traps", "blocks": [{"type": "bullet", "text": "terraform fmt and validate do not deploy infrastructure."}, {"type": "bullet", "text": "terraform plan previews; terraform apply performs changes."}, {"type": "bullet", "text": "A saved plan is different from generating a fresh plan during apply."}, {"type": "bullet", "text": "Textual block order does not define provisioning order."}, {"type": "bullet", "text": "depends_on should represent a real dependency, not arbitrary sequencing."}, {"type": "bullet", "text": "A resource address uses Terraform's local names, not necessarily cloud display names."}, {"type": "bullet", "text": "Provider, resource, and data source are different concepts."}]}], "lead": "workflow commands, configuration blocks and files, plans, resource addresses, dependencies, saved plans, and providers."}, {"id": "6", "title": "Jenkins", "full_title": "Jenkins", "icon": "jenkins", "sections": [{"title": "6.1 Controller and agent architecture", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Jenkins controller", "Stores job and Pipeline definitions, provides the web interface, schedules work, manages users, credentials, and plugins, and assigns builds."], ["Jenkins agent", "Executes assigned build commands, maintains the build workspace, and returns logs, status, and results."], ["Workspace", "Directory on an agent where a build checks out files and performs work."], ["Executor", "A slot on a node that can run build work."]]}, {"type": "callout", "title": "Why production systems separate them", "body": [{"type": "paragraph", "text": "Compiling software and building container images can consume substantial CPU, memory, and disk. Running that work on agents keeps the controller responsive and allows several specialized or scalable build machines."}]}]}, {"title": "6.7 Jenkins Production Architecture and Vocabulary", "blocks": [{"type": "table", "rows": [["Term", "Meaning"], ["Job", "Saved automation definition."], ["Build", "One execution of a job."], ["Workspace", "The build's working directory on the executing node."], ["Plugin", "An extension that adds Jenkins capabilities."], ["Node", "Any machine that can execute builds; the built-in node is the controller."], ["Executor", "One concurrent-build slot on a node."], ["Label", "A selector used to target suitable agents."]]}, {"type": "callout", "title": "Why builds should not run on the controller", "body": [{"type": "paragraph", "text": "Builds are CPU-, memory-, and disk-intensive."}, {"type": "paragraph", "text": "Build code may be untrusted and can expose controller credentials or destabilize the service."}, {"type": "paragraph", "text": "Agents isolate heavy and risky work while the controller remains responsive."}]}, {"type": "callout", "title": "Class best practice", "body": [{"type": "paragraph", "text": "Set built-in node executors to 0 after agents are configured."}, {"type": "paragraph", "text": "If executors are set to 0 before any agent exists, jobs wait because there is nowhere to run."}]}, {"type": "bullet", "text": "Permanent agents remain available."}, {"type": "bullet", "text": "Cloud or container agents can start for a build and disappear afterward."}, {"type": "bullet", "text": "Mounting the Docker socket allows containerized Jenkins to create or manage containers."}]}, {"title": "6.2 Build triggers", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Manual build", "A user explicitly starts the job."], ["Webhook", "The repository host sends an event, allowing a build to begin immediately after a push."], ["Poll SCM", "Jenkins checks the repository on a schedule and starts a build only when it detects changes."], ["Scheduled build", "Runs the job on a schedule regardless of whether the source changed."], ["Upstream-job trigger", "Starts after another Jenkins job reaches the configured result."]]}, {"type": "callout", "title": "Poll SCM versus scheduled build", "body": [{"type": "paragraph", "text": "Poll SCM schedules repository checks and builds only when changes are found. A scheduled build runs unconditionally at the selected time. Polling is useful when a webhook cannot reach Jenkins."}]}]}, {"title": "6.8 Trigger Selection Scenarios", "blocks": [{"type": "table", "rows": [["Situation", "Best trigger"], ["Repository host can reach Jenkins", "Webhook"], ["Jenkins is private or behind NAT", "Poll SCM"], ["Run every night regardless of source changes", "Build periodically"], ["Start deployment after another job succeeds", "Upstream-job trigger"], ["One-off testing", "Manual build"]]}, {"type": "callout", "title": "Why polling exists", "body": [{"type": "paragraph", "text": "A private Jenkins server may not accept an inbound webhook, but it can make outbound repository checks."}]}]}, {"title": "6.3 Freestyle job sections", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Source Code Management", "Repository URL, branch, and checkout credentials."], ["Build Triggers", "Manual/event/schedule conditions that start the job."], ["Build Environment", "Environment preparation, credential bindings, and setup wrappers."], ["Build Steps", "Shell commands, compilation, testing, and packaging."], ["Post-build Actions", "Notifications, reports, archived outputs, and downstream actions."]]}, {"type": "callout", "title": "Classification examples", "body": [{"type": "paragraph", "text": "Repository URL -> Source Code Management. Polling schedule -> Build Triggers. Credential binding -> Build Environment. docker build or pytest -> Build Steps. Notification -> Post-build Actions."}]}]}, {"title": "6.4 Declarative Pipeline organization", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["pipeline", "Top-level Declarative Pipeline block."], ["agent", "Selects the machine or execution environment."], ["stages", "Container holding one or more stage blocks."], ["stage", "Names a meaningful workflow phase such as Checkout, Test, or Package."], ["steps", "Execution block containing the commands and Pipeline operations for a stage."], ["Individual step", "An operation such as checkout, sh, bat, echo, or archiveArtifacts."], ["post", "Result-dependent actions that run after a stage or the whole Pipeline."]]}, {"type": "codeblock", "language": "Jenkinsfile", "text": "pipeline {\n  agent any\n\n  stages {\n    stage('Checkout') {\n      steps {\n        checkout scm\n      }\n    }\n\n    stage('Test') {\n      steps {\n        sh 'pytest'\n      }\n    }\n\n    stage('Package') {\n      steps {\n        sh 'docker build -t app .'\n      }\n    }\n  }\n\n  post {\n    always {\n      sh 'docker rm -f test-container || true'\n    }\n  }\n}"}]}, {"title": "6.9 Complete Declarative Pipeline Example", "blocks": [{"type": "codeblock", "language": "Jenkinsfile", "text": "pipeline {\n  agent { label 'docker-agent' }\n\n  stages {\n    stage('Checkout') {\n      steps {\n        git 'https://github.com/user/repo.git'\n      }\n    }\n\n    stage('Test') {\n      steps {\n        sh 'pytest'\n      }\n    }\n\n    stage('Package') {\n      steps {\n        sh 'docker build -t app .'\n      }\n    }\n  }\n\n  post {\n    always {\n      sh 'docker rm -f test-db || true'\n    }\n\n    success {\n      echo 'good'\n    }\n\n    failure {\n      echo 'broken'\n    }\n  }\n}"}, {"type": "bullet", "text": "Pipeline hierarchy: pipeline → agent → stages → stage → steps → individual steps."}, {"type": "bullet", "text": "post sits alongside stages at the Pipeline level, or inside an individual stage."}, {"type": "bullet", "text": "Stages provide separate status and timing so failures are easier to locate."}, {"type": "bullet", "text": "Different stages can target different agents or enforce gates."}, {"type": "exam_answer", "text": "Exam-ready answer: A stage names a phase; executable operations belong inside steps."}]}, {"title": "6.5 Post-run behavior", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["always", "Run after every result."], ["success", "Run only after success."], ["failure", "Run only after failure."], ["changed", "Run when the result changed compared with the previous completed build."], ["unstable", "Run when the build is unstable."], ["cleanup", "Run during final cleanup after other post conditions."]]}, {"type": "callout", "title": "Why cleanup should not be an ordinary final stage", "body": [{"type": "paragraph", "text": "An earlier stage failure can prevent later normal stages from running. Place must-run teardown in post with always or cleanup so temporary containers are removed even when Checkout, Test, or Package fails."}]}]}, {"title": "6.10 Complete Post Conditions", "blocks": [{"type": "table", "rows": [["Condition", "When it runs"], ["always", "After every result."], ["success", "Only after success."], ["failure", "Only after failure."], ["changed", "When the result differs from the previous build."], ["unstable", "When the build is unstable."], ["cleanup", "Last, after the other post conditions."]]}, {"type": "callout", "title": "Why cleanup is not a final stage", "body": [{"type": "paragraph", "text": "A failed earlier stage can stop later normal stages. Must-run teardown belongs in post with always or cleanup."}]}]}, {"title": "6.6 Common exam traps", "blocks": [{"type": "bullet", "text": "The controller coordinates and administers; the agent executes assigned build commands."}, {"type": "bullet", "text": "Poll SCM and an unconditional schedule are not the same trigger."}, {"type": "bullet", "text": "A stage names a phase; executable operations belong inside steps."}, {"type": "bullet", "text": "A normal final stage can be skipped after failure."}, {"type": "bullet", "text": "Must-run cleanup belongs in post always or cleanup."}, {"type": "bullet", "text": "Freestyle repository settings belong in Source Code Management, not Build Steps."}]}], "lead": "controller-agent architecture, build triggers, Freestyle job sections, Declarative Pipeline hierarchy, and post-run cleanup."}, {"id": "9", "title": "Solution Methods", "full_title": "Complete Literal Subtopic and Problem-Solving Guide", "icon": "solutions", "sections": [{"title": "Overview", "blocks": [{"type": "paragraph", "text": "This section closes every remaining gap. It explains exactly what each listed subtopic means, what command or concept to use, what result to expect, and how to write the short answer."}]}, {"title": "A. Git and GitHub - Complete Solution Methods", "blocks": [{"type": "callout", "title": "HOW TO SOLVE IT: Identify where a Git change lives", "body": [{"type": "paragraph", "text": "1. New file never added -> untracked in the working directory.\n2. Tracked file edited after its staged/committed version -> modified.\n3. Change copied with git add -> staged in the index.\n4. Snapshot created with git commit -> repository history.\n5. Untracked path matching an ignore rule -> ignored.\n6. Remember that one file can contain staged content and newer unstaged edits at the same time.\nExam-ready answer: Name both the state and the snapshot: working directory, staging area, or repository history."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Choose the correct Git inspection command", "body": [{"type": "paragraph", "text": "1. General summary -> git status.\n2. Working directory versus staging area -> git diff.\n3. Staging area versus HEAD -> git diff --staged.\n4. Ignored-file visibility -> git status --ignored.\n5. Why a path is ignored -> git check-ignore -v path.\n6. Files and patch in a completed commit -> git show COMMIT.\nExam-ready answer: State the comparison boundary, not only the command name."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Resolve a merge conflict literally", "body": [{"type": "paragraph", "text": "1. Run git status and list every unmerged path.\n2. Open the file and find <<<<<<<, =======, and >>>>>>> markers.\n3. Choose the current-branch content, incoming content, or a correct manual combination.\n4. Delete every conflict marker.\n5. Test or inspect the completed file.\n6. Run git add resolved-file to mark it resolved.\n7. Repeat for all conflicted files and run git status again.\n8. Run git commit to complete the merge.\n9. Use git merge --abort instead when the merge should be abandoned.\nExam-ready answer: Edit -> remove markers -> test -> git add -> git commit; or git merge --abort to cancel."}]}, {"type": "callout", "title": "Merge source and destination", "body": [{"type": "paragraph", "text": "The branch currently checked out is always the destination. The branch written after git merge is the source. Example: git switch main followed by git merge feature means feature is merged into main."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Find which Git configuration supplied an identity", "body": [{"type": "paragraph", "text": "1. Remember precedence: local overrides global, and global overrides system.\n2. Run git config --list --show-origin or git config --show-origin --get user.email.\n3. Read the path of the configuration file that supplied the effective value.\n4. Explain that the effective name/email is written into new commit metadata.\nExam-ready answer: A repository-local identity affects that repository without changing other repositories."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Ignore an already tracked local file", "body": [{"type": "paragraph", "text": "1. Add the path to .gitignore.\n2. Run git rm --cached path to stage removal from tracking while keeping the local file.\n3. Commit the .gitignore rule and tracking removal.\n4. Verify with git ls-files, git status, and git status --ignored.\n5. Rotate any credential that was already committed because history may still contain it.\nExam-ready answer: .gitignore affects untracked paths; git rm --cached is required to stop existing tracking."}]}]}, {"title": "B. Docker - Complete Solution Methods", "blocks": [{"type": "table", "rows": [["Concept / Command", "Complete literal explanation"], ["Container writable layer", "Private to one container and normally removed with that container."], ["Named volume persistence", "The volume exists independently of the container and normally survives container removal until explicitly deleted."], ["Bind mount persistence", "The data exists at the chosen host path and remains after container removal."], ["Source-code suitability", "Bind mounts are useful when the host must edit and immediately expose source code."], ["Database-data suitability", "Named volumes are normally preferred because Docker manages the persistent location."]]}, {"type": "callout", "title": "HOW TO SOLVE IT: Choose container-local storage, a named volume, or a bind mount", "body": [{"type": "paragraph", "text": "1. Ask whether the data must survive container removal.\n2. Disposable data -> writable layer may be acceptable.\n3. Specific host path or live source editing -> bind mount.\n4. Docker-managed persistent application/database data -> named volume.\n5. State who chooses the location and whether the data persists.\nExam-ready answer: Source code often uses a bind mount; database data normally uses a named volume."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Solve a container-networking question", "body": [{"type": "paragraph", "text": "1. Confirm the containers share a user-defined network.\n2. Use a container name or Compose service name instead of a saved IP address.\n3. Use the internal container port for container-to-container traffic.\n4. Publish a host port only when traffic must enter from outside the Docker network.\n5. Explain that containers on isolated networks cannot automatically communicate.\nExam-ready answer: Internal traffic uses service-name:container-port; external traffic uses host-address:published-port."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Fix a Dockerfile that reinstalls dependencies after source changes", "body": [{"type": "paragraph", "text": "1. Copy dependency descriptor files first.\n2. Install dependencies in the next layer.\n3. Copy the rest of the source afterward.\n4. Add irrelevant and sensitive files to .dockerignore.\n5. Rebuild and verify that the dependency-install step uses cache when descriptors are unchanged.\n6. Apply the same pattern to requirements.txt, package-lock.json, pom.xml, go.mod, Cargo.lock, or equivalent files.\nExam-ready answer: Dependency files -> dependency install -> application source."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Replace startup behavior during docker run", "body": [{"type": "paragraph", "text": "1. Determine whether the normal web process is configured in CMD or ENTRYPOINT.\n2. A command after the image name normally replaces CMD or becomes ENTRYPOINT arguments.\n3. Use --entrypoint to replace ENTRYPOINT itself.\n4. Use -i to keep input open and -t for a terminal only when needed.\n5. Verify that the diagnostic executable or shell exists in the minimal image.\nExam-ready answer: Runtime command replaces CMD; --entrypoint replaces ENTRYPOINT."}]}]}, {"title": "C. AWS - Complete Solution Methods", "blocks": [{"type": "callout", "title": "HOW TO SOLVE IT: Troubleshoot an unreachable containerized EC2 application", "body": [{"type": "paragraph", "text": "1. Confirm the EC2 instance is running and has the intended public IP or public DNS.\n2. Check the subnet route table and internet gateway.\n3. Check the security-group inbound protocol, host port, and source CIDR.\n4. Check the operating-system firewall.\n5. Check Docker's published HOST:CONTAINER mapping.\n6. Check that the container is running and inspect its logs.\n7. Check that the application listens on the correct container port.\n8. Check that the application binds to 0.0.0.0 or another reachable interface rather than only 127.0.0.1.\nExam-ready answer: Troubleshoot from AWS network -> security group -> OS firewall -> Docker port mapping -> container -> application."}]}, {"type": "table", "rows": [["Storage point", "Complete decision rule"], ["S3", "Object storage accessed through bucket/key and APIs. Designed for extremely high object durability."], ["EBS", "Block storage attached as a disk to EC2. Use snapshots/backups for additional recovery; the volume is tied to an Availability Zone."], ["EFS", "Managed shared network filesystem that multiple instances can mount."], ["Access pattern", "Object requests -> S3; disk/block reads and writes -> EBS; shared filesystem operations -> EFS."], ["Attachment", "When storage must be attached as a disk to one EC2 instance, select EBS."], ["Durability decision", "Consider service durability plus snapshots, backups, multi-AZ/regional design, and recovery requirements."]]}, {"type": "callout", "title": "HOW TO SOLVE IT: Restore an S3 object hidden by deletion", "body": [{"type": "paragraph", "text": "1. Confirm versioning is enabled.\n2. List versions and delete markers rather than ordinary objects only.\n3. Find the current delete marker.\n4. Delete that marker to reveal the prior version, or copy a chosen older version to create a new current version.\n5. To permanently delete one version, specify that version ID.\n6. Explain that versioning is not an independent backup by itself.\nExam-ready answer: A current delete marker hides the key without automatically erasing all earlier versions."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Compare Linux and Windows EC2 remote access", "body": [{"type": "paragraph", "text": "1. Linux: SSH, TCP 22, SSH client, image-specific user, key or configured SSH credentials.\n2. Windows: RDP, TCP 3389, Remote Desktop client, Windows credentials.\n3. For both, the security group must allow the management port from a restricted source.\nExam-ready answer: Linux = SSH/22; Windows = RDP/3389, with different clients and credentials."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Apply least privilege", "body": [{"type": "paragraph", "text": "1. Identify the principal: user, group member, role, or AWS service.\n2. Identify the exact actions required.\n3. Identify the exact resources required.\n4. Add conditions or time/context limits when possible.\n5. Keep IAM permission separate from network permission: an IAM allow does not open a port.\n6. Use S3 Block Public Access and private policies unless public access is truly required.\nExam-ready answer: Grant only the required actions on the required resources for the required context."}]}]}, {"title": "D. Linux - Complete Solution Methods", "blocks": [{"type": "callout", "title": "HOW TO SOLVE IT: Choose temporary assignment versus export", "body": [{"type": "paragraph", "text": "1. NAME=value sets a shell variable.\n2. export NAME=value makes it available to future child processes.\n3. NAME=value command supplies it only to one command invocation.\n4. Use echo \"$NAME\" to display a value.\nExam-ready answer: One command -> NAME=value command; current shell and children -> export NAME=value."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Find why the wrong executable runs", "body": [{"type": "paragraph", "text": "1. Run type command-name.\n2. Run command -v command-name.\n3. Display PATH and read directories from left to right.\n4. The first matching executable normally wins.\n5. Move unsafe writable directories later or remove them, then update the correct startup file for persistence.\nExam-ready answer: PATH order matters; an unsafe early directory can shadow the intended command."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Evaluate redirections left to right", "body": [{"type": "paragraph", "text": "1. Begin with STDIN=0, STDOUT=1, STDERR=2.\n2. Process each redirection in written order.\n3. When 2>&1 appears, copy descriptor 1's current destination to descriptor 2.\n4. Later changes to descriptor 1 do not retroactively change descriptor 2.\n5. State the final destination of both streams.\nExam-ready answer: command > file 2>&1 sends both to file; command 2>&1 > file normally leaves STDERR on the terminal."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Construct a file with a here-document", "body": [{"type": "paragraph", "text": "1. Use a command such as cat and redirect to the destination file.\n2. Begin with <<EOF or another delimiter.\n3. Write the multiline content.\n4. Quote the delimiter when variables and command substitutions must remain literal.\n5. Place the exact closing delimiter alone at the beginning of a line.\nExam-ready answer: cat > file <<EOF ... EOF, with exact delimiter spelling and placement."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Explain logical versus physical path", "body": [{"type": "paragraph", "text": "1. A logical path preserves the symbolic-link name used during navigation.\n2. A physical path resolves symbolic links to the actual filesystem destination.\n3. Use pwd -L for logical and pwd -P for physical.\n4. Both strings can identify the same directory.\nExam-ready answer: Logical = route used; physical = resolved destination."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Navigate without retyping paths", "body": [{"type": "paragraph", "text": "1. cd ~ goes home.\n2. cd .. goes to the parent.\n3. An absolute path begins at /.\n4. A relative path begins from the current directory.\n5. cd - returns to the previous working directory and can alternate between two locations.\nExam-ready answer: Use cd - for the previously visited directory."}]}]}, {"title": "E. Terraform - Complete Solution Methods", "blocks": [{"type": "callout", "title": "HOW TO SOLVE IT: Choose the correct Terraform workflow command", "body": [{"type": "paragraph", "text": "1. Prepare providers/modules/backend -> terraform init.\n2. Canonical formatting -> terraform fmt.\n3. Syntax/internal consistency -> terraform validate.\n4. Preview proposed actions -> terraform plan.\n5. Perform approved actions -> terraform apply.\n6. Display output blocks -> terraform output.\n7. Remove managed infrastructure -> terraform destroy.\n8. State that fmt, validate, and plan do not normally change infrastructure.\nExam-ready answer: Choose by workflow stage and say what the command does not change."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Read a Terraform plan beyond the summary", "body": [{"type": "paragraph", "text": "1. + means create.\n2. ~ means update in place.\n3. - means destroy.\n4. -/+ or +/- means replacement.\n5. known after apply means the value is unavailable until execution.\n6. Inspect the resource body and changed attributes; do not rely only on the final counts.\n7. Look for an attribute that forces replacement.\nExam-ready answer: Explain both the action symbol and the attribute that caused it."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Parse a Terraform resource address", "body": [{"type": "paragraph", "text": "1. Read any module path first.\n2. Identify the resource type.\n3. Identify the local resource name.\n4. Identify count indexes or for_each keys in brackets.\n5. Identify an attribute when one follows.\n6. Do not assume the local Terraform name equals the external cloud name.\nExam-ready answer: Module -> resource type -> local name -> instance key/index -> attribute."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Decide between implicit and explicit dependency", "body": [{"type": "paragraph", "text": "1. Look for an attribute reference from one block to another.\n2. A reference creates an implicit dependency and is preferred.\n3. Use depends_on only when a real hidden ordering requirement cannot be expressed through data flow.\n4. Unnecessary depends_on reduces parallelism and may make more values unknown.\n5. Textual order in a .tf file does not control provisioning order.\nExam-ready answer: Prefer references; use depends_on only for a justified hidden dependency."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Explain a saved plan", "body": [{"type": "paragraph", "text": "1. terraform plan -out=tfplan creates the reviewed artifact.\n2. terraform apply tfplan applies that exact artifact.\n3. terraform apply without the file creates a fresh plan.\n4. A saved plan improves predictability because reviewed actions are applied.\n5. Configuration, variable, state, provider, credential, endpoint, or real-infrastructure changes can make it stale.\nExam-ready answer: Saved plans freeze reviewed actions but must be regenerated when assumptions change."}]}, {"type": "table", "rows": [["Concept / Command", "Complete literal explanation"], ["Provider plugin", "The integration executable that communicates with an external platform."], ["Required-provider declaration", "Specifies source and acceptable version."], ["Provider configuration", "Sets region, endpoint, alias, and platform options."], ["Installation", "terraform init downloads the provider and records its selected version/checksum in .terraform.lock.hcl."], ["Authentication", "The provider obtains credentials through supported environment, files, roles, or platform-specific mechanisms."], ["API translation", "The provider converts Terraform create/read/update/delete plans into authenticated platform API operations and returns resulting state."], ["Resource", "A managed object whose lifecycle Terraform controls."], ["Data source", "An existing object or value Terraform reads without managing creation."]]}]}, {"title": "F. Jenkins - Complete Solution Methods", "blocks": [{"type": "callout", "title": "HOW TO SOLVE IT: Separate controller and agent responsibilities", "body": [{"type": "paragraph", "text": "1. Controller stores definitions, provides UI, schedules work, manages users/credentials/plugins, and assigns builds.\n2. Agent executes commands, owns the workspace, and returns logs/results.\n3. Move compilation, tests, and container builds to agents.\n4. Use multiple or specialized agents for scale and platform/tool differences.\nExam-ready answer: Controller coordinates; agents execute."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Choose a trigger", "body": [{"type": "paragraph", "text": "1. Immediate GitHub push -> webhook.\n2. Jenkins cannot receive inbound repository events -> Poll SCM.\n3. Run every Sunday regardless of changes -> scheduled build / Build periodically.\n4. Run after another Jenkins job -> upstream-job trigger.\n5. Start only when a person chooses -> manual build.\nExam-ready answer: Poll SCM checks for changes; Build periodically runs unconditionally."}]}, {"type": "table", "rows": [["Freestyle item", "Correct section"], ["Repository URL, branch, checkout credential", "Source Code Management."], ["Webhook, Poll SCM, schedule, upstream condition", "Build Triggers."], ["Credential binding, environment setup, wrappers", "Build Environment."], ["Shell commands, compile, test, package, docker build", "Build Steps."], ["Reports, artifacts, notifications, downstream action", "Post-build Actions."], ["Cleanup in Freestyle", "Use an available Build Environment wrapper when cleanup surrounds execution, or an appropriate Post-build Action/plugin. In Pipeline, use post always/cleanup."]]}, {"type": "callout", "title": "HOW TO SOLVE IT: Organize a Declarative Pipeline", "body": [{"type": "paragraph", "text": "1. pipeline is the top level.\n2. agent selects the execution environment.\n3. stages contains stage blocks.\n4. Each stage names a meaningful phase.\n5. Executable operations belong inside steps.\n6. post contains result-dependent behavior.\n7. Separate stages improve logs, timing, visualization, failure location, and stage-specific control.\nExam-ready answer: pipeline -> agent -> stages -> stage -> steps; use post for result behavior."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Guarantee cleanup after failure", "body": [{"type": "paragraph", "text": "1. Do not depend on a normal final stage because later stages can be skipped after failure.\n2. Place cleanup in Pipeline-level post.\n3. Use always for every result or cleanup for final cleanup after other post conditions.\n4. Make the command tolerant when the resource may not exist.\nExam-ready answer: Use post { always { ... } } or post { cleanup { ... } }."}]}, {"type": "callout", "title": "100% coverage statement", "body": [{"type": "paragraph", "text": "This master expansion explicitly includes the five previously under-explained points: literal Git conflict resolution; named-volume and bind-mount persistence after container removal; AWS storage access-pattern and durability selection; provider translation into platform API operations; and Freestyle cleanup classification."}]}]}], "lead": ""}, {"id": "7", "title": "Practice Questions", "full_title": "Instructor Practice Questions", "icon": "practice", "sections": [{"title": "Overview", "blocks": [{"type": "paragraph", "text": "The original list repeated number 14. The questions below preserve every prompt while using a clean 1-25 sequence."}, {"type": "callout", "title": "1. A developer wants to compare changes made but not yet staged with changes already selected for the next commit. What distinction must the developer understand when choosing Git inspection commands?", "body": []}, {"type": "callout", "title": "2. What command displays the current state of the working directory and staging area?", "body": []}, {"type": "callout", "title": "3. What command stages all current changes in the repository directory?", "body": []}, {"type": "callout", "title": "4. What is the purpose of a Git commit?", "body": []}, {"type": "callout", "title": "5. A Docker image rebuild takes several minutes because application dependencies are reinstalled every time any source file changes. Explain how Dockerfile structure and the build cache can improve this process.", "body": []}, {"type": "callout", "title": "6. What command displays the images stored locally?", "body": []}, {"type": "callout", "title": "7. An image normally starts a web application automatically. During troubleshooting, an engineer needs the container to start a diagnostic executable instead. Explain the distinction between replacing the image's default command and replacing its configured entrypoint.", "body": []}, {"type": "callout", "title": "8. What does VPC stand for, and what is its basic purpose in AWS?", "body": []}, {"type": "callout", "title": "9. An application works when tested directly on an EC2 instance but cannot be reached from another computer. Describe the major network and security layers that should be examined, beginning at AWS and ending at the application process.", "body": []}, {"type": "callout", "title": "10. A company operates both Linux and Windows EC2 instances. Compare the normal remote-management requirements for the two operating systems.", "body": []}, {"type": "callout", "title": "11. What does IAM stand for?", "body": []}, {"type": "callout", "title": "12. A workload requires files accessed as independent web-addressable objects, a disk attached to one EC2 instance, and a shared filesystem mounted by several instances. Identify the appropriate general AWS storage category or service for each requirement.", "body": []}, {"type": "callout", "title": "13. Consider command > output.log 2>&1 and command 2>&1 > output.log. Explain why these commands can produce different results even though they contain the same redirection operators.", "body": []}, {"type": "callout", "title": "14. A symbolic link named current points to a versioned release directory. An administrator enters the directory through current, but a diagnostic tool reports the underlying release path. Explain why both paths can be correct and what each represents.", "body": []}, {"type": "callout", "title": "15. A user frequently alternates between two distant directories. Describe the shell navigation feature that returns to the last directory without storing or retyping its full pathname.", "body": []}, {"type": "callout", "title": "16. A plan reports that one resource will be updated in place while another must be replaced. Explain the practical difference between these proposed actions.", "body": []}, {"type": "callout", "title": "17. What file extension is normally used for Terraform configuration files?", "body": []}, {"type": "callout", "title": "18. What command removes the infrastructure managed by the current Terraform configuration?", "body": []}, {"type": "callout", "title": "19. A deployment team creates and approves a Terraform plan on Monday but waits until Friday to apply it. Explain why applying that saved plan may be safer than generating a new unreviewed plan, and identify a reason the saved plan might no longer be usable.", "body": []}, {"type": "callout", "title": "20. What is a Jenkins controller?", "body": []}, {"type": "callout", "title": "21. What is the purpose of a Jenkins agent?", "body": []}, {"type": "callout", "title": "22. A Jenkins installation becomes slow because the central server is managing users, rendering the web interface, scheduling jobs, compiling applications, and building container images. Describe how controller-agent architecture could improve this design.", "body": []}, {"type": "callout", "title": "23. Select and justify the most appropriate Jenkins trigger for: (a) a build immediately after a GitHub push, (b) Jenkins cannot receive inbound requests from the repository host, and (c) a maintenance process must run every Sunday regardless of code changes.", "body": []}, {"type": "callout", "title": "24. A Pipeline contains stages named Checkout, Test, and Package. Explain why placing every command in one large execution block is less useful than separate stages with their own steps.", "body": []}, {"type": "callout", "title": "25. A Pipeline creates temporary containers during testing. The containers must be removed even when checkout, testing, or packaging fails. Describe how cleanup should be organized and why a normal final stage may be unreliable.", "body": []}, {"type": "heading", "text": "How to Answer the Practice Questions Literally"}, {"type": "paragraph", "text": "Use this after attempting the questions yourself. Each recipe identifies exactly what the grader is looking for."}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 1: Git unstaged versus staged changes", "body": [{"type": "paragraph", "text": "1. Say which snapshots are compared.\n2. Use git diff for working tree vs index.\n3. Use git diff --staged for index vs HEAD.\nExam-ready answer: git diff; git diff --staged."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 2: Git status", "body": [{"type": "paragraph", "text": "1. The wording says current state, not full patch.\n2. Use the summary command.\nExam-ready answer: git status."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 3: Stage current repository changes", "body": [{"type": "paragraph", "text": "1. The path . means the current directory.\n2. git add copies current content into the index.\nExam-ready answer: git add ."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 4: Purpose of commit", "body": [{"type": "paragraph", "text": "1. Name the staging area as input.\n2. Name repository history as output.\nExam-ready answer: A commit records the staged snapshot in repository history."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 5: Docker dependency cache", "body": [{"type": "paragraph", "text": "1. Copy descriptors.\n2. Install dependencies.\n3. Copy source last.\nExam-ready answer: Order stable dependency layers before changing source layers."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 6: List Docker images", "body": [{"type": "paragraph", "text": "1. Do not answer docker ps; that lists containers.\nExam-ready answer: docker images or docker image ls."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 7: CMD versus ENTRYPOINT", "body": [{"type": "paragraph", "text": "1. Runtime command normally replaces CMD.\n2. --entrypoint replaces ENTRYPOINT.\nExam-ready answer: Command after image -> CMD; --entrypoint -> ENTRYPOINT."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 8: VPC meaning", "body": [{"type": "paragraph", "text": "1. Expand acronym.\n2. State isolated logical AWS network purpose.\nExam-ready answer: Virtual Private Cloud."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 9: Unreachable EC2 application", "body": [{"type": "paragraph", "text": "1. Go outside-in from AWS routing to process binding.\nExam-ready answer: Route/IGW -> SG -> OS firewall -> host port -> container port -> listen address."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 10: Linux versus Windows EC2", "body": [{"type": "paragraph", "text": "1. Protocol, port, client, credentials, SG source.\nExam-ready answer: SSH/22 versus RDP/3389."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 11: IAM meaning", "body": [{"type": "paragraph", "text": "1. Expand acronym exactly.\nExam-ready answer: Identity and Access Management."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 12: AWS storage choices", "body": [{"type": "paragraph", "text": "1. Objects, block disk, shared filesystem.\nExam-ready answer: S3, EBS, EFS."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 13: Redirection order", "body": [{"type": "paragraph", "text": "1. Process left to right.\n2. 2>&1 copies current STDOUT destination.\nExam-ready answer: First sends both to file; second normally keeps STDERR on terminal."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 14: Logical and physical path", "body": [{"type": "paragraph", "text": "1. Symbolic-link route versus resolved destination.\nExam-ready answer: pwd -L versus pwd -P."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 15: Previous directory", "body": [{"type": "paragraph", "text": "1. Use shell's previous working directory feature.\nExam-ready answer: cd -."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 16: Terraform update versus replacement", "body": [{"type": "paragraph", "text": "1. Same object versus new object plus old destruction.\nExam-ready answer: In-place changes existing; replacement recreates."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 17: Terraform extension", "body": [{"type": "paragraph", "text": "1. Recall configuration file suffix.\nExam-ready answer: .tf."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 18: Terraform destroy command", "body": [{"type": "paragraph", "text": "1. Use destruction phase command.\nExam-ready answer: terraform destroy."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 19: Saved Terraform plan", "body": [{"type": "paragraph", "text": "1. Reviewed exact actions; stale if assumptions changed.\nExam-ready answer: Apply saved plan only while configuration/state/infrastructure remain valid."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 20: Jenkins controller", "body": [{"type": "paragraph", "text": "1. Central administration and scheduling responsibilities.\nExam-ready answer: Controller coordinates."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 21: Jenkins agent", "body": [{"type": "paragraph", "text": "1. Execution, workspace, logs/results.\nExam-ready answer: Agent executes."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 22: Controller-agent improvement", "body": [{"type": "paragraph", "text": "1. Move heavy work off controller.\nExam-ready answer: Agents improve responsiveness and scale."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 23: Jenkins triggers", "body": [{"type": "paragraph", "text": "1. Push -> webhook; no inbound -> Poll SCM; Sunday regardless -> schedule.\nExam-ready answer: Webhook, Poll SCM, Build periodically."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 24: Separate Pipeline stages", "body": [{"type": "paragraph", "text": "1. Visibility, timing, logs, failure location, stage controls.\nExam-ready answer: Commands belong inside each stage's steps."}]}, {"type": "callout", "title": "HOW TO SOLVE IT: Question 25: Reliable Pipeline cleanup", "body": [{"type": "paragraph", "text": "1. Final normal stage may be skipped.\n2. Use post always or cleanup.\nExam-ready answer: post { always { ... } } or post { cleanup { ... } }."}]}]}], "lead": ""}, {"id": "8", "title": "Answer Key", "full_title": "Answer Key", "icon": "answers", "sections": [{"title": "Overview", "blocks": [{"type": "callout", "title": "1. A developer wants to compare changes made but not yet staged with changes already selected for the next commit. What distinction must the developer understand when choosing Git inspection commands?", "body": [{"type": "paragraph", "text": "Answer: Use git diff for unstaged working-directory changes versus the staging area. Use git diff --staged (or --cached) for staged changes versus the most recent commit."}]}, {"type": "callout", "title": "2. What command displays the current state of the working directory and staging area?", "body": [{"type": "paragraph", "text": "Answer: git status."}]}, {"type": "callout", "title": "3. What command stages all current changes in the repository directory?", "body": [{"type": "paragraph", "text": "Answer: git add . is the usual expected answer for the current repository directory. git add -A stages across the entire working tree."}]}, {"type": "callout", "title": "4. What is the purpose of a Git commit?", "body": [{"type": "paragraph", "text": "Answer: A commit records the staged project snapshot in repository history with metadata and a message."}]}, {"type": "callout", "title": "5. A Docker image rebuild takes several minutes because application dependencies are reinstalled every time any source file changes. Explain how Dockerfile structure and the build cache can improve this process.", "body": [{"type": "paragraph", "text": "Answer: Copy dependency files first, install dependencies, and copy frequently changing source afterward. Docker can reuse the dependency layer until its inputs or an earlier layer change."}]}, {"type": "callout", "title": "6. What command displays the images stored locally?", "body": [{"type": "paragraph", "text": "Answer: docker images or docker image ls."}]}, {"type": "callout", "title": "7. An image normally starts a web application automatically. During troubleshooting, an engineer needs the container to start a diagnostic executable instead. Explain the distinction between replacing the image's default command and replacing its configured entrypoint.", "body": [{"type": "paragraph", "text": "Answer: A command after the image name normally replaces CMD or supplies arguments to ENTRYPOINT. --entrypoint replaces the configured ENTRYPOINT executable itself."}]}, {"type": "callout", "title": "8. What does VPC stand for, and what is its basic purpose in AWS?", "body": [{"type": "paragraph", "text": "Answer: Virtual Private Cloud. It is the isolated logical AWS network containing resources, IP ranges, subnets, routes, and network controls."}]}, {"type": "callout", "title": "9. An application works when tested directly on an EC2 instance but cannot be reached from another computer. Describe the major network and security layers that should be examined, beginning at AWS and ending at the application process.", "body": [{"type": "paragraph", "text": "Answer: Check the public IP/DNS, route table and internet gateway, security-group source/protocol/host port, OS firewall, Docker host-to-container port mapping, container state, and the application's listen address and port."}]}, {"type": "callout", "title": "10. A company operates both Linux and Windows EC2 instances. Compare the normal remote-management requirements for the two operating systems.", "body": [{"type": "paragraph", "text": "Answer: Linux normally uses SSH on TCP 22 with an SSH client and key/user credentials. Windows normally uses RDP on TCP 3389 with a Remote Desktop client and Windows credentials. Both need correct routing and a restricted security-group rule."}]}, {"type": "callout", "title": "11. What does IAM stand for?", "body": [{"type": "paragraph", "text": "Answer: Identity and Access Management."}]}, {"type": "callout", "title": "12. A workload requires files accessed as independent web-addressable objects, a disk attached to one EC2 instance, and a shared filesystem mounted by several instances. Identify the appropriate general AWS storage category or service for each requirement.", "body": [{"type": "paragraph", "text": "Answer: Independent web objects: S3 object storage. One EC2 disk: EBS block storage. Shared mounted filesystem: EFS file storage."}]}, {"type": "callout", "title": "13. Consider command > output.log 2>&1 and command 2>&1 > output.log. Explain why these commands can produce different results even though they contain the same redirection operators.", "body": [{"type": "paragraph", "text": "Answer: Redirections are processed left to right. In > file 2>&1, STDERR copies the already redirected STDOUT destination. In 2>&1 > file, STDERR copies the original terminal destination before STDOUT is redirected."}]}, {"type": "callout", "title": "14. A symbolic link named current points to a versioned release directory. An administrator enters the directory through current, but a diagnostic tool reports the underlying release path. Explain why both paths can be correct and what each represents.", "body": [{"type": "paragraph", "text": "Answer: The logical path preserves the route through the symbolic link; the physical path resolves the link to the actual release directory. Both identify the same physical location."}]}, {"type": "callout", "title": "15. A user frequently alternates between two distant directories. Describe the shell navigation feature that returns to the last directory without storing or retyping its full pathname.", "body": [{"type": "paragraph", "text": "Answer: cd - returns to the previous working directory."}]}, {"type": "callout", "title": "16. A plan reports that one resource will be updated in place while another must be replaced. Explain the practical difference between these proposed actions.", "body": [{"type": "paragraph", "text": "Answer: An in-place update modifies the existing object. Replacement creates a new object and destroys the old one, possibly changing identifiers, causing downtime, or temporarily duplicating resources."}]}, {"type": "callout", "title": "17. What file extension is normally used for Terraform configuration files?", "body": [{"type": "paragraph", "text": "Answer: .tf."}]}, {"type": "callout", "title": "18. What command removes the infrastructure managed by the current Terraform configuration?", "body": [{"type": "paragraph", "text": "Answer: terraform destroy."}]}, {"type": "callout", "title": "19. A deployment team creates and approves a Terraform plan on Monday but waits until Friday to apply it. Explain why applying that saved plan may be safer than generating a new unreviewed plan, and identify a reason the saved plan might no longer be usable.", "body": [{"type": "paragraph", "text": "Answer: The saved plan applies the exact actions that were reviewed instead of producing a fresh unreviewed plan. It may become stale or unusable if configuration, variables, state, providers, credentials, or real infrastructure change."}]}, {"type": "callout", "title": "20. What is a Jenkins controller?", "body": [{"type": "paragraph", "text": "Answer: The controller is the central Jenkins coordination and administration component. It stores definitions, provides the UI, schedules and assigns work, and manages users, credentials, and plugins."}]}, {"type": "callout", "title": "21. What is the purpose of a Jenkins agent?", "body": [{"type": "paragraph", "text": "Answer: An agent supplies executors and a workspace where assigned build commands run, then returns logs and results."}]}, {"type": "callout", "title": "22. A Jenkins installation becomes slow because the central server is managing users, rendering the web interface, scheduling jobs, compiling applications, and building container images. Describe how controller-agent architecture could improve this design.", "body": [{"type": "paragraph", "text": "Answer: Keep scheduling and administration on the controller while moving compilation and image builds to agents. This improves controller responsiveness, scalability, isolation, and support for specialized environments."}]}, {"type": "callout", "title": "23. Select and justify the most appropriate Jenkins trigger for: (a) a build immediately after a GitHub push, (b) Jenkins cannot receive inbound requests from the repository host, and (c) a maintenance process must run every Sunday regardless of code changes.", "body": [{"type": "paragraph", "text": "Answer: Immediate GitHub push: webhook. No inbound requests: Poll SCM. Every Sunday regardless of changes: scheduled build or Build periodically."}]}, {"type": "callout", "title": "24. A Pipeline contains stages named Checkout, Test, and Package. Explain why placing every command in one large execution block is less useful than separate stages with their own steps.", "body": [{"type": "paragraph", "text": "Answer: Separate stages improve visualization, timing, logs, failure location, and stage-specific behavior. Executable commands belong inside each stage's steps block."}]}, {"type": "callout", "title": "25. A Pipeline creates temporary containers during testing. The containers must be removed even when checkout, testing, or packaging fails. Describe how cleanup should be organized and why a normal final stage may be unreliable.", "body": [{"type": "paragraph", "text": "Answer: Place cleanup in post with always or cleanup. A normal final stage may be skipped when an earlier stage fails."}]}, {"type": "paragraph", "text": "APPENDIX A"}]}], "lead": ""}, {"id": "10", "title": "Rapid Reference", "full_title": "Rapid Command Reference", "icon": "reference", "sections": [{"title": "Overview", "blocks": [{"type": "heading", "text": "Git"}, {"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["git status", "Overall working-tree and staging status."], ["git diff", "Unstaged changes."], ["git diff --staged", "Staged changes."], ["git add .", "Stage current-directory changes."], ["git commit -m \"message\"", "Commit the staged snapshot."], ["git branch / git switch", "List branches / change branches."], ["git merge branch", "Merge branch into the current branch."], ["git merge --abort", "Cancel an unfinished merge."], ["git status --ignored", "Show ignored files."], ["git check-ignore -v file", "Show the matching ignore rule."], ["git config --list --show-origin", "Show settings and their source files."]]}]}, {"title": "Docker commands", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["docker images", "List local images."], ["docker ps / docker ps -a", "Running containers / all containers."], ["docker run -it IMAGE sh", "Interactive terminal when sh exists."], ["docker run -p 8080:80 IMAGE", "Publish host port 8080 to container port 80."], ["docker run --entrypoint EXE IMAGE", "Replace ENTRYPOINT."], ["docker volume create NAME", "Create a named volume."], ["docker network create NAME", "Create a user-defined network."]]}]}, {"title": "Linux commands", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["echo \"$NAME\"", "Display a variable."], ["export NAME=value", "Export a variable to child processes."], ["command -v name", "Show what the shell would run."], ["cmd > out 2> err", "Separate normal output and errors."], ["cmd > all 2>&1", "Send both streams to one file."], ["pwd -L / pwd -P", "Logical path / physical path."], ["cd ~ / cd .. / cd -", "Home / parent / previous directory."]]}]}, {"title": "Terraform commands", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["terraform init", "Initialize."], ["terraform fmt", "Format."], ["terraform validate", "Validate."], ["terraform plan", "Preview."], ["terraform plan -out=tfplan", "Save a plan."], ["terraform apply tfplan", "Apply the saved plan."], ["terraform output", "Display outputs."], ["terraform destroy", "Remove managed infrastructure."]]}]}, {"title": "Jenkins commands", "blocks": [{"type": "table", "rows": [["Command / Concept", "Meaning and exam use"], ["Webhook", "Immediate repository event."], ["Poll SCM", "Check for repository changes on a schedule."], ["Build periodically", "Run unconditionally on a schedule."], ["post { always { ... } }", "Run must-do actions after any result."], ["post { cleanup { ... } }", "Final cleanup after other post conditions."]]}]}], "lead": ""}, {"id": "11", "title": "Coverage Checklist", "full_title": "Topic Coverage Checklist", "icon": "checklist", "sections": [{"title": "Overview", "blocks": [{"type": "bullet", "text": "Git working directory, staging area, history, tracked, untracked, modified, staged, and ignored states"}, {"type": "bullet", "text": "Git status, unstaged diff, staged diff, ignored-file display, ignore verification, and commit inspection"}, {"type": "bullet", "text": "Git branch creation/switching, current branch, merge source/destination, fast-forward, merge commit, conflicts, and abort"}, {"type": "bullet", "text": "Git system, global, and local configuration scopes, commit identity, and configuration origin"}, {"type": "bullet", "text": "Git ignore-rule purpose, tracked-file limitation, verification, status display, and common exclusions"}, {"type": "bullet", "text": "Dockerfiles, images, containers, layers, writable layer, and registries"}, {"type": "bullet", "text": "Docker named volumes, bind mounts, portability, persistence, and source-code versus database use"}, {"type": "bullet", "text": "Docker user-defined networks, isolation, name resolution, container/Compose service names, and port publishing"}, {"type": "bullet", "text": "Docker build context, .dockerignore, cache reuse, instruction order, dependency files, and invalidation"}, {"type": "bullet", "text": "Docker CMD, ENTRYPOINT, runtime command arguments, --entrypoint, -i/-t, and minimal-image shells"}, {"type": "bullet", "text": "AWS browser-to-EC2-to-Docker-to-application request path"}, {"type": "bullet", "text": "AWS security groups, ports, protocols, source CIDRs, public IPs, internet gateways, routes, OS firewalls, and listen addresses"}, {"type": "bullet", "text": "Linux versus Windows EC2 remote access"}, {"type": "bullet", "text": "S3 version IDs, current/noncurrent versions, delete markers, restoration, permanent deletion, and backups"}, {"type": "bullet", "text": "AWS object storage, block storage, shared file storage, and service selection"}, {"type": "bullet", "text": "EC2 basics, VPCs, subnets, routes, internet gateways, security groups, IAM, EBS persistence, S3 protection, and least privilege"}, {"type": "bullet", "text": "Linux environment variables, temporary assignment, export, startup configuration, PATH order, command lookup, and unsafe paths"}, {"type": "bullet", "text": "Linux STDIN, STDOUT, STDERR, file descriptors, overwrite, append, separate/combined redirection, pipes, and operator order"}, {"type": "bullet", "text": "Linux here-document delimiters, file output, quoting, expansion, and closing-delimiter rules"}, {"type": "bullet", "text": "Linux symbolic links, logical paths, physical paths, current directory, and resolved destination"}, {"type": "bullet", "text": "Linux home, parent, absolute, relative, previous directory, pwd -L, and pwd -P"}, {"type": "bullet", "text": "Terraform workflow, commands, resource/data/variable/local/output blocks, tfvars, references, .terraform, and lock file"}, {"type": "bullet", "text": "Terraform plan symbols, unknown values, final summary, and attribute-level cause"}, {"type": "bullet", "text": "Terraform resource type, local name, attributes, module paths, indexes, and for_each keys"}, {"type": "bullet", "text": "Terraform implicit/explicit dependencies, justified depends_on, parallelism, and non-significance of textual order"}, {"type": "bullet", "text": "Terraform saved-plan creation, review, application, fresh-plan distinction, and staleness"}, {"type": "bullet", "text": "Terraform provider plugins, declarations, configuration, sources, constraints, installation, authentication, API translation, resource/data distinction"}, {"type": "bullet", "text": "Jenkins controller/agent responsibilities and production separation"}, {"type": "bullet", "text": "Jenkins manual, webhook, Poll SCM, scheduled, and upstream triggers"}, {"type": "bullet", "text": "Jenkins Freestyle SCM, triggers, environment, build steps, and post-build actions"}, {"type": "bullet", "text": "Jenkins pipeline, agent, stages, stage, steps, individual steps, and post"}, {"type": "bullet", "text": "Jenkins always, success, failure, changed, unstable, cleanup, and reliable teardown"}]}], "lead": ""}], "qa": [{"n": 1, "q": "A developer wants to compare changes made but not yet staged with changes already selected for the next commit. What distinction must the developer understand when choosing Git inspection commands?", "a": "Use git diff for unstaged working-directory changes versus the staging area. Use git diff --staged (or --cached) for staged changes versus the most recent commit."}, {"n": 2, "q": "What command displays the current state of the working directory and staging area?", "a": "git status."}, {"n": 3, "q": "What command stages all current changes in the repository directory?", "a": "git add . is the usual expected answer for the current repository directory. git add -A stages across the entire working tree."}, {"n": 4, "q": "What is the purpose of a Git commit?", "a": "A commit records the staged project snapshot in repository history with metadata and a message."}, {"n": 5, "q": "A Docker image rebuild takes several minutes because application dependencies are reinstalled every time any source file changes. Explain how Dockerfile structure and the build cache can improve this process.", "a": "Copy dependency files first, install dependencies, and copy frequently changing source afterward. Docker can reuse the dependency layer until its inputs or an earlier layer change."}, {"n": 6, "q": "What command displays the images stored locally?", "a": "docker images or docker image ls."}, {"n": 7, "q": "An image normally starts a web application automatically. During troubleshooting, an engineer needs the container to start a diagnostic executable instead. Explain the distinction between replacing the image's default command and replacing its configured entrypoint.", "a": "A command after the image name normally replaces CMD or supplies arguments to ENTRYPOINT. --entrypoint replaces the configured ENTRYPOINT executable itself."}, {"n": 8, "q": "What does VPC stand for, and what is its basic purpose in AWS?", "a": "Virtual Private Cloud. It is the isolated logical AWS network containing resources, IP ranges, subnets, routes, and network controls."}, {"n": 9, "q": "An application works when tested directly on an EC2 instance but cannot be reached from another computer. Describe the major network and security layers that should be examined, beginning at AWS and ending at the application process.", "a": "Check the public IP/DNS, route table and internet gateway, security-group source/protocol/host port, OS firewall, Docker host-to-container port mapping, container state, and the application's listen address and port."}, {"n": 10, "q": "A company operates both Linux and Windows EC2 instances. Compare the normal remote-management requirements for the two operating systems.", "a": "Linux normally uses SSH on TCP 22 with an SSH client and key/user credentials. Windows normally uses RDP on TCP 3389 with a Remote Desktop client and Windows credentials. Both need correct routing and a restricted security-group rule."}, {"n": 11, "q": "What does IAM stand for?", "a": "Identity and Access Management."}, {"n": 12, "q": "A workload requires files accessed as independent web-addressable objects, a disk attached to one EC2 instance, and a shared filesystem mounted by several instances. Identify the appropriate general AWS storage category or service for each requirement.", "a": "Independent web objects: S3 object storage. One EC2 disk: EBS block storage. Shared mounted filesystem: EFS file storage."}, {"n": 13, "q": "Consider command > output.log 2>&1 and command 2>&1 > output.log. Explain why these commands can produce different results even though they contain the same redirection operators.", "a": "Redirections are processed left to right. In > file 2>&1, STDERR copies the already redirected STDOUT destination. In 2>&1 > file, STDERR copies the original terminal destination before STDOUT is redirected."}, {"n": 14, "q": "A symbolic link named current points to a versioned release directory. An administrator enters the directory through current, but a diagnostic tool reports the underlying release path. Explain why both paths can be correct and what each represents.", "a": "The logical path preserves the route through the symbolic link; the physical path resolves the link to the actual release directory. Both identify the same physical location."}, {"n": 15, "q": "A user frequently alternates between two distant directories. Describe the shell navigation feature that returns to the last directory without storing or retyping its full pathname.", "a": "cd - returns to the previous working directory."}, {"n": 16, "q": "A plan reports that one resource will be updated in place while another must be replaced. Explain the practical difference between these proposed actions.", "a": "An in-place update modifies the existing object. Replacement creates a new object and destroys the old one, possibly changing identifiers, causing downtime, or temporarily duplicating resources."}, {"n": 17, "q": "What file extension is normally used for Terraform configuration files?", "a": ".tf."}, {"n": 18, "q": "What command removes the infrastructure managed by the current Terraform configuration?", "a": "terraform destroy."}, {"n": 19, "q": "A deployment team creates and approves a Terraform plan on Monday but waits until Friday to apply it. Explain why applying that saved plan may be safer than generating a new unreviewed plan, and identify a reason the saved plan might no longer be usable.", "a": "The saved plan applies the exact actions that were reviewed instead of producing a fresh unreviewed plan. It may become stale or unusable if configuration, variables, state, providers, credentials, or real infrastructure change."}, {"n": 20, "q": "What is a Jenkins controller?", "a": "The controller is the central Jenkins coordination and administration component. It stores definitions, provides the UI, schedules and assigns work, and manages users, credentials, and plugins."}, {"n": 21, "q": "What is the purpose of a Jenkins agent?", "a": "An agent supplies executors and a workspace where assigned build commands run, then returns logs and results."}, {"n": 22, "q": "A Jenkins installation becomes slow because the central server is managing users, rendering the web interface, scheduling jobs, compiling applications, and building container images. Describe how controller-agent architecture could improve this design.", "a": "Keep scheduling and administration on the controller while moving compilation and image builds to agents. This improves controller responsiveness, scalability, isolation, and support for specialized environments."}, {"n": 23, "q": "Select and justify the most appropriate Jenkins trigger for: (a) a build immediately after a GitHub push, (b) Jenkins cannot receive inbound requests from the repository host, and (c) a maintenance process must run every Sunday regardless of code changes.", "a": "Immediate GitHub push: webhook. No inbound requests: Poll SCM. Every Sunday regardless of changes: scheduled build or Build periodically."}, {"n": 24, "q": "A Pipeline contains stages named Checkout, Test, and Package. Explain why placing every command in one large execution block is less useful than separate stages with their own steps.", "a": "Separate stages improve visualization, timing, logs, failure location, and stage-specific behavior. Executable commands belong inside each stage's steps block."}, {"n": 25, "q": "A Pipeline creates temporary containers during testing. The containers must be removed even when checkout, testing, or packaging fails. Describe how cleanup should be organized and why a normal final stage may be unreliable.", "a": "Place cleanup in post with always or cleanup. A normal final stage may be skipped when an earlier stage fails.\nAPPENDIX A"}], "traps": [{"chapter": "Git and GitHub", "text": "git diff and git diff --staged inspect different states."}, {"chapter": "Git and GitHub", "text": "A commit records the staged snapshot, not every file currently on disk."}, {"chapter": "Git and GitHub", "text": "git commit -a does not include new untracked files."}, {"chapter": "Git and GitHub", "text": "The current branch is the merge destination."}, {"chapter": "Git and GitHub", "text": ".gitignore does not automatically untrack an existing file."}, {"chapter": "Git and GitHub", "text": "Local configuration overrides global and system settings for one repository."}, {"chapter": "Docker", "text": "A container is an instance of an image, not the same object."}, {"chapter": "Docker", "text": "The writable layer is not reliable persistent storage."}, {"chapter": "Docker", "text": "A container name or Compose service name is safer than a hard-coded container IP."}, {"chapter": "Docker", "text": "In -p HOST:CONTAINER, the left side is the host port."}, {"chapter": "Docker", "text": ".dockerignore limits the build context; it is separate from .gitignore."}, {"chapter": "Docker", "text": "A command after the image name does not necessarily replace ENTRYPOINT."}, {"chapter": "Docker", "text": "Minimal images may not contain bash."}, {"chapter": "AWS", "text": "A public IP does not guarantee reachability."}, {"chapter": "AWS", "text": "Security groups and operating-system firewalls are separate layers."}, {"chapter": "AWS", "text": "Host port and container port are not necessarily the same number."}, {"chapter": "AWS", "text": "SSH and RDP use different ports, clients, and credential methods."}, {"chapter": "AWS", "text": "An S3 delete marker can hide an object without erasing every version."}, {"chapter": "AWS", "text": "Versioning is not a complete backup strategy."}, {"chapter": "AWS", "text": "S3 is object storage, EBS is block storage, and EFS is shared file storage."}, {"chapter": "Linux", "text": "Setting a shell variable and exporting it are not the same operation."}, {"chapter": "Linux", "text": "PATH is searched in order from left to right."}, {"chapter": "Linux", "text": "A pipe sends STDOUT unless STDERR is explicitly combined."}, {"chapter": "Linux", "text": "Redirection order changes the result because file-descriptor duplication is time-sensitive."}, {"chapter": "Linux", "text": "Quoted and unquoted here-document delimiters handle expansion differently."}, {"chapter": "Linux", "text": "pwd -L and pwd -P can show different strings for the same directory."}, {"chapter": "Linux", "text": "cd - means the previously visited directory, not the parent directory."}, {"chapter": "Terraform", "text": "terraform fmt and validate do not deploy infrastructure."}, {"chapter": "Terraform", "text": "terraform plan previews; terraform apply performs changes."}, {"chapter": "Terraform", "text": "A saved plan is different from generating a fresh plan during apply."}, {"chapter": "Terraform", "text": "Textual block order does not define provisioning order."}, {"chapter": "Terraform", "text": "depends_on should represent a real dependency, not arbitrary sequencing."}, {"chapter": "Terraform", "text": "A resource address uses Terraform's local names, not necessarily cloud display names."}, {"chapter": "Terraform", "text": "Provider, resource, and data source are different concepts."}, {"chapter": "Jenkins", "text": "The controller coordinates and administers; the agent executes assigned build commands."}, {"chapter": "Jenkins", "text": "Poll SCM and an unconditional schedule are not the same trigger."}, {"chapter": "Jenkins", "text": "A stage names a phase; executable operations belong inside steps."}, {"chapter": "Jenkins", "text": "A normal final stage can be skipped after failure."}, {"chapter": "Jenkins", "text": "Must-run cleanup belongs in post always or cleanup."}, {"chapter": "Jenkins", "text": "Freestyle repository settings belong in Source Code Management, not Build Steps."}], "flashcards": [{"chapter": "Git and GitHub", "front": "Working directory", "back": "The files currently present on disk, including edits that may not be staged."}, {"chapter": "Git and GitHub", "front": "Staging area / index", "back": "The exact snapshot Git will use for the next commit."}, {"chapter": "Git and GitHub", "front": "Repository history", "back": "Completed commits stored in the repository."}, {"chapter": "Git and GitHub", "front": "Tracked file", "back": "A file Git already knows about through the index or history."}, {"chapter": "Git and GitHub", "front": "Untracked file", "back": "A new file that has never been added to Git."}, {"chapter": "Git and GitHub", "front": "Modified file", "back": "A tracked file whose working-directory contents changed."}, {"chapter": "Git and GitHub", "front": "Staged file", "back": "A change copied into the index for the next commit."}, {"chapter": "Git and GitHub", "front": "Ignored file", "back": "An untracked path matching an ignore rule and normally hidden from ordinary status output."}, {"chapter": "Git and GitHub", "front": "git status", "back": "Shows the overall state of the current branch, staging area, working tree, and untracked files."}, {"chapter": "Git and GitHub", "front": "git diff", "back": "Shows unstaged changes: working directory compared with the staging area."}, {"chapter": "Git and GitHub", "front": "git diff --staged", "back": "Shows staged changes: staging area compared with the most recent commit. --cached is a synonym."}, {"chapter": "Git and GitHub", "front": "git status --ignored", "back": "Displays ignored files in addition to normal status information."}, {"chapter": "Git and GitHub", "front": "git check-ignore -v path", "back": "Verifies that a path matches an ignore rule and shows the rule and file that supplied it."}, {"chapter": "Git and GitHub", "front": "git show COMMIT", "back": "Shows a commit's metadata and patch."}, {"chapter": "Git and GitHub", "front": "git show --stat COMMIT", "back": "Shows the files and summary statistics included in a commit."}, {"chapter": "Git and GitHub", "front": "git add file", "back": "Stage the current contents of one file."}, {"chapter": "Git and GitHub", "front": "git add .", "back": "Stage current changes under the current directory, including new, modified, and deleted paths."}, {"chapter": "Git and GitHub", "front": "git add -A", "back": "Stage changes across the entire working tree."}, {"chapter": "Git and GitHub", "front": "git commit -m \"message\"", "back": "Create a commit from the staged snapshot."}, {"chapter": "Git and GitHub", "front": "git commit -a -m \"message\"", "back": "Automatically stage tracked modifications/deletions, then commit; untracked files are excluded."}, {"chapter": "Git and GitHub", "front": "git restore --staged file", "back": "Unstage a change without discarding the working-directory edit."}, {"chapter": "Git and GitHub", "front": "git branch feature-login", "back": "Create a branch without switching to it."}, {"chapter": "Git and GitHub", "front": "git branch", "back": "List local branches and mark the current branch."}, {"chapter": "Git and GitHub", "front": "git switch feature-login", "back": "Switch to an existing branch."}, {"chapter": "Git and GitHub", "front": "git switch -c feature-login", "back": "Create and switch to a new branch."}, {"chapter": "Git and GitHub", "front": "git checkout feature-login", "back": "Older command that can switch branches."}, {"chapter": "Git and GitHub", "front": "git merge feature-login", "back": "Merge feature-login into the currently checked-out branch."}, {"chapter": "Git and GitHub", "front": "git status", "back": "During a conflict, shows unmerged paths and required next steps."}, {"chapter": "Git and GitHub", "front": "git add resolved-file", "back": "Mark the edited conflict resolution as staged."}, {"chapter": "Git and GitHub", "front": "git commit", "back": "Complete the merge after all conflicts are resolved and staged."}, {"chapter": "Git and GitHub", "front": "git merge --abort", "back": "Cancel the unfinished merge and return to the pre-merge state when possible."}, {"chapter": "Git and GitHub", "front": "System", "back": "Applies broadly to users and repositories on the computer."}, {"chapter": "Git and GitHub", "front": "Global", "back": "Applies to the current user's repositories unless overridden."}, {"chapter": "Git and GitHub", "front": "Local repository", "back": "Stored inside one repository and overrides broader settings for that repository."}, {"chapter": "Git and GitHub", "front": "git config --system --list", "back": "Display system-scope settings."}, {"chapter": "Git and GitHub", "front": "git config --global --list", "back": "Display global settings."}, {"chapter": "Git and GitHub", "front": "git config --local --list", "back": "Display repository-local settings."}, {"chapter": "Git and GitHub", "front": "git config --list --show-origin", "back": "Show effective settings and the configuration file that supplied each value."}, {"chapter": "Git and GitHub", "front": "git config user.name", "back": "Show the effective commit author name."}, {"chapter": "Git and GitHub", "front": "git config user.email", "back": "Show the effective commit author email."}, {"chapter": "Git and GitHub", "front": ".gitignore", "back": "Repository file containing ignore patterns."}, {"chapter": "Git and GitHub", "front": "git status --ignored", "back": "Show ignored paths while checking repository status."}, {"chapter": "Git and GitHub", "front": "git check-ignore -v file", "back": "Verify which rule ignores a path."}, {"chapter": "Git and GitHub", "front": "git rm --cached file", "back": "Stop tracking the file while keeping the local copy."}, {"chapter": "Git and GitHub", "front": "git rm -r --cached directory/", "back": "Stop tracking a directory tree while keeping local copies."}, {"chapter": "Git and GitHub", "front": "git ls-files", "back": "List files currently tracked by Git."}, {"chapter": "Docker", "front": "Dockerfile", "back": "Text instructions used to build an image."}, {"chapter": "Docker", "front": "Image", "back": "Read-only packaged filesystem and startup metadata used as a container template."}, {"chapter": "Docker", "front": "Container", "back": "A runnable instance of an image with its own process and runtime state."}, {"chapter": "Docker", "front": "Image layer", "back": "A reusable filesystem/build result created by an image-building instruction."}, {"chapter": "Docker", "front": "Writable layer", "back": "Container-specific top layer that stores runtime filesystem changes."}, {"chapter": "Docker", "front": "Registry", "back": "A service that stores and distributes images, such as Docker Hub."}, {"chapter": "Docker", "front": "Container-local writable layer", "back": "Tied to one container and normally removed with it; unsuitable for important persistent data."}, {"chapter": "Docker", "front": "Named volume", "back": "Docker chooses and manages the host storage location. Commonly used for database and application data."}, {"chapter": "Docker", "front": "Bind mount", "back": "The user chooses an exact host path and mounts it into the container. Commonly used for source code and configuration."}, {"chapter": "Docker", "front": "docker volume create dbdata", "back": "Create a named volume."}, {"chapter": "Docker", "front": "docker run --mount type=volume,src=dbdata,dst=/var/lib/data IMAGE", "back": "Mount Docker-managed persistent storage."}, {"chapter": "Docker", "front": "docker run --mount type=bind,src=$PWD,dst=/app IMAGE", "back": "Mount the current host directory into /app."}, {"chapter": "Docker", "front": "docker volume ls", "back": "List Docker-managed volumes."}, {"chapter": "Docker", "front": "docker network create appnet", "back": "Create a user-defined network."}, {"chapter": "Docker", "front": "docker run --network appnet --name db IMAGE", "back": "Attach a container named db to the network."}, {"chapter": "Docker", "front": "docker run --network appnet --name api IMAGE", "back": "The api container can use db as the destination name."}, {"chapter": "Docker", "front": "-p 8080:80", "back": "Publish host port 8080 and forward it to container port 80."}, {"chapter": "Docker", "front": "docker network inspect appnet", "back": "Inspect network configuration and connected containers."}, {"chapter": "Docker", "front": "CMD", "back": "Sets a default command or default arguments. A command after the image name commonly replaces CMD."}, {"chapter": "Docker", "front": "ENTRYPOINT", "back": "Sets the primary executable. Runtime arguments are commonly appended to an exec-form ENTRYPOINT."}, {"chapter": "Docker", "front": "docker run IMAGE command", "back": "Supplies a runtime command after the image name; normally replaces CMD or becomes ENTRYPOINT arguments."}, {"chapter": "Docker", "front": "--entrypoint executable", "back": "Replaces the image's configured ENTRYPOINT."}, {"chapter": "Docker", "front": "-i", "back": "Keeps standard input open."}, {"chapter": "Docker", "front": "-t", "back": "Allocates a pseudo-terminal. Often combined as -it."}, {"chapter": "Docker", "front": "sh / bash", "back": "A shell must actually exist in the image. Minimal images may not include bash or any interactive shell."}, {"chapter": "Docker", "front": "docker images", "back": "Display images stored locally. docker image ls is the equivalent object-style command."}, {"chapter": "Docker", "front": "docker ps", "back": "Display running containers."}, {"chapter": "Docker", "front": "docker ps -a", "back": "Display running and stopped containers."}, {"chapter": "Docker", "front": "docker run -it IMAGE sh", "back": "Start an interactive terminal when sh exists."}, {"chapter": "Docker", "front": "docker logs CONTAINER", "back": "Display the container's output and errors."}, {"chapter": "AWS", "front": "Security-group inbound rule", "back": "Allows a specific protocol and destination port from a source CIDR or security group."}, {"chapter": "AWS", "front": "Protocol and port range", "back": "Must match the service, such as TCP 80, 443, 22, or 3389."}, {"chapter": "AWS", "front": "Source CIDR", "back": "Defines which client addresses are allowed. x.x.x.x/32 represents one IPv4 address."}, {"chapter": "AWS", "front": "Public IPv4 / public DNS", "back": "Provides an internet-reachable address when combined with correct routing."}, {"chapter": "AWS", "front": "Internet gateway", "back": "Connects the VPC to the public internet."}, {"chapter": "AWS", "front": "Route table", "back": "Directs destination traffic to a target, such as 0.0.0.0/0 to an internet gateway."}, {"chapter": "AWS", "front": "Host port", "back": "The port exposed on the EC2 operating system."}, {"chapter": "AWS", "front": "Container port", "back": "The internal port on which the containerized service listens."}, {"chapter": "AWS", "front": "OS firewall", "back": "A separate security layer inside the instance."}, {"chapter": "AWS", "front": "Application listen address", "back": "Determines which interfaces the process accepts connections on."}, {"chapter": "AWS", "front": "Linux EC2", "back": "Normally managed with SSH over TCP 22 using an SSH client, the correct image-specific user name, and a private key or other configured authentication."}, {"chapter": "AWS", "front": "Windows EC2", "back": "Normally managed with RDP over TCP 3389 using a Remote Desktop client and Windows credentials."}, {"chapter": "AWS", "front": "Security group", "back": "Must permit the correct management port from a suitably restricted source."}, {"chapter": "AWS", "front": "VPC", "back": "Virtual Private Cloud: the isolated logical AWS network that contains resources and network configuration."}, {"chapter": "AWS", "front": "Subnet", "back": "A smaller IP range inside the VPC, associated with one Availability Zone."}, {"chapter": "AWS", "front": "Public subnet", "back": "Has a route to an internet gateway and supports internet-facing resources with public addressing."}, {"chapter": "AWS", "front": "Private subnet", "back": "Does not directly expose its instances to the internet through an internet gateway."}, {"chapter": "AWS", "front": "Route table", "back": "Contains destination-and-target rules controlling where traffic goes."}, {"chapter": "AWS", "front": "0.0.0.0/0", "back": "The IPv4 default route, matching destinations not covered by a more specific route."}, {"chapter": "AWS", "front": "Internet gateway", "back": "A VPC component used for public internet connectivity."}, {"chapter": "AWS", "front": "IAM user", "back": "An identity representing a person or application when a long-lived IAM identity is appropriate."}, {"chapter": "AWS", "front": "IAM group", "back": "A collection of users used to assign permissions at scale."}, {"chapter": "AWS", "front": "IAM role", "back": "An assumable identity that supplies temporary permissions, commonly used by AWS services and workloads."}, {"chapter": "AWS", "front": "IAM policy", "back": "A JSON permission document that allows or denies actions on resources under specified conditions."}, {"chapter": "AWS", "front": "Least privilege", "back": "Grant only the permissions required to complete the task."}, {"chapter": "AWS", "front": "Amazon S3", "back": "Object storage for independent objects addressed by bucket and key. Suitable for web content, logs, backups, and large-scale object access."}, {"chapter": "AWS", "front": "Amazon EBS", "back": "Persistent block storage presented as a disk to EC2. Suitable for operating-system volumes and workloads needing a block device."}, {"chapter": "AWS", "front": "Amazon EFS", "back": "Managed shared file storage that multiple instances can mount. Included because the practice question asks about a shared filesystem."}, {"chapter": "AWS", "front": "Instance store", "back": "Temporary block storage physically attached to the host; not appropriate when data must survive the instance lifecycle."}, {"chapter": "Linux", "front": "echo \"$HOME\"", "back": "Display the value of one environment variable."}, {"chapter": "Linux", "front": "NAME=value", "back": "Set a variable in the current shell."}, {"chapter": "Linux", "front": "export NAME=value", "back": "Set and export a variable to subsequently started child processes."}, {"chapter": "Linux", "front": "NAME=value command", "back": "Temporarily set a variable only for one command invocation."}, {"chapter": "Linux", "front": "echo \"$PATH\"", "back": "Display the command-search path."}, {"chapter": "Linux", "front": "command -v python", "back": "Show the command the shell would execute."}, {"chapter": "Linux", "front": "type cd", "back": "Explain whether a name is a shell builtin, alias, function, or external command."}, {"chapter": "Linux", "front": "~/.bashrc", "back": "A common Bash startup file used for interactive-shell aliases and exports."}, {"chapter": "Linux", "front": "0 - STDIN", "back": "Standard Input: where a process receives input."}, {"chapter": "Linux", "front": "1 - STDOUT", "back": "Standard Output: normal program output."}, {"chapter": "Linux", "front": "2 - STDERR", "back": "Standard Error: diagnostic and error output."}, {"chapter": "Linux", "front": "> file", "back": "Redirect STDOUT and overwrite the file."}, {"chapter": "Linux", "front": ">> file", "back": "Redirect STDOUT and append to the file."}, {"chapter": "Linux", "front": "2> file", "back": "Redirect STDERR and overwrite the file."}, {"chapter": "Linux", "front": "2>> file", "back": "Redirect STDERR and append to the file."}, {"chapter": "Linux", "front": "command > all.log 2>&1", "back": "Send STDOUT to the file, then duplicate STDERR to the same destination."}, {"chapter": "Linux", "front": "command 2>&1 > output.log", "back": "Duplicate STDERR to the original STDOUT destination, then redirect only STDOUT to the file."}, {"chapter": "Linux", "front": "command > out.log 2> err.log", "back": "Keep normal output and errors in separate files."}, {"chapter": "Linux", "front": "|", "back": "Pipe the left command's STDOUT into the right command's STDIN."}, {"chapter": "Linux", "front": "|&", "back": "In Bash, pipe both STDOUT and STDERR."}, {"chapter": "Linux", "front": "ln -s target link_name", "back": "Create a symbolic link."}, {"chapter": "Linux", "front": "pwd", "back": "Print the current working directory, normally using the shell's logical path."}, {"chapter": "Linux", "front": "pwd -L", "back": "Explicitly display the logical path."}, {"chapter": "Linux", "front": "pwd -P", "back": "Resolve symbolic links and display the physical path."}, {"chapter": "Linux", "front": "readlink link_name", "back": "Display the stored target of a symbolic link."}, {"chapter": "Linux", "front": "cd ~", "back": "Go to the current user's home directory."}, {"chapter": "Linux", "front": "cd", "back": "With no argument, normally also goes to the home directory."}, {"chapter": "Linux", "front": "cd ..", "back": "Go to the parent directory."}, {"chapter": "Linux", "front": "cd /absolute/path", "back": "Navigate using a path beginning at the filesystem root."}, {"chapter": "Linux", "front": "cd relative/path", "back": "Navigate relative to the current working directory."}, {"chapter": "Linux", "front": "cd -", "back": "Return to the previous working directory and normally print it."}, {"chapter": "Linux", "front": "pwd -L", "back": "Display the logical current directory."}, {"chapter": "Linux", "front": "pwd -P", "back": "Display the resolved physical directory."}, {"chapter": "Terraform", "front": "terraform init", "back": "Initialize the working directory and install required providers and modules."}, {"chapter": "Terraform", "front": "terraform fmt", "back": "Rewrite configuration using standard formatting. It does not change infrastructure."}, {"chapter": "Terraform", "front": "terraform validate", "back": "Check syntax and internal consistency. It does not deploy resources."}, {"chapter": "Terraform", "front": "terraform plan", "back": "Preview proposed infrastructure actions without applying them."}, {"chapter": "Terraform", "front": "terraform apply", "back": "Create a plan and, after approval, perform the changes."}, {"chapter": "Terraform", "front": "terraform output", "back": "Display values declared by output blocks."}, {"chapter": "Terraform", "front": "terraform destroy", "back": "Plan and remove the infrastructure managed through the current state/configuration."}, {"chapter": "Terraform", "front": "Resource block", "back": "Declares an infrastructure object Terraform manages."}, {"chapter": "Terraform", "front": "Data block", "back": "Reads information about an existing object without managing its creation."}, {"chapter": "Terraform", "front": "Input variable", "back": "Allows a value to be supplied to the configuration."}, {"chapter": "Terraform", "front": "Local value", "back": "A named expression used inside a module to avoid repetition."}, {"chapter": "Terraform", "front": "Output block", "back": "Exposes a selected result."}, {"chapter": "Terraform", "front": "Variable-definition file", "back": "Supplies values, commonly through terraform.tfvars or *.auto.tfvars."}, {"chapter": "Terraform", "front": "Reference", "back": "Uses another block's attribute, such as aws_instance.web.id."}, {"chapter": "Terraform", "front": ".terraform directory", "back": "Stores working-directory data such as installed providers/modules and backend information; normally not committed."}, {"chapter": "Terraform", "front": ".terraform.lock.hcl", "back": "Dependency lock file recording selected provider versions and checksums; normally committed."}, {"chapter": "Terraform", "front": ".tf", "back": "Normal Terraform configuration-file extension."}, {"chapter": "Terraform", "front": "+", "back": "Create a resource."}, {"chapter": "Terraform", "front": "~", "back": "Modify a resource in place."}, {"chapter": "Terraform", "front": "-", "back": "Destroy a resource."}, {"chapter": "Terraform", "front": "-/+ or +/-", "back": "Replace a resource by destroying and creating in the order shown."}, {"chapter": "Terraform", "front": "known after apply", "back": "The value cannot be calculated until the operation runs."}, {"chapter": "Terraform", "front": "Plan: X to add, Y to change, Z to destroy", "back": "Summary of proposed actions. Still inspect the attribute-level cause."}, {"chapter": "Terraform", "front": "aws_instance.web", "back": "Resource type aws_instance and local Terraform name web."}, {"chapter": "Terraform", "front": "aws_instance.web.id", "back": "The id attribute of that resource."}, {"chapter": "Terraform", "front": "module.network.aws_subnet.public", "back": "A resource inside the child module named network."}, {"chapter": "Terraform", "front": "aws_instance.web[0]", "back": "An indexed instance created with count."}, {"chapter": "Terraform", "front": "aws_instance.web[\"blue\"]", "back": "An instance selected by a for_each key."}, {"chapter": "Terraform", "front": "terraform plan -out=tfplan", "back": "Generate and save a specific plan artifact for review."}, {"chapter": "Terraform", "front": "terraform apply tfplan", "back": "Apply the saved artifact without generating a new plan."}, {"chapter": "Terraform", "front": "terraform apply", "back": "Without a saved file, Terraform generates a new plan during the apply process."}, {"chapter": "Jenkins", "front": "Jenkins controller", "back": "Stores job and Pipeline definitions, provides the web interface, schedules work, manages users, credentials, and plugins, and assigns builds."}, {"chapter": "Jenkins", "front": "Jenkins agent", "back": "Executes assigned build commands, maintains the build workspace, and returns logs, status, and results."}, {"chapter": "Jenkins", "front": "Workspace", "back": "Directory on an agent where a build checks out files and performs work."}, {"chapter": "Jenkins", "front": "Executor", "back": "A slot on a node that can run build work."}, {"chapter": "Jenkins", "front": "Manual build", "back": "A user explicitly starts the job."}, {"chapter": "Jenkins", "front": "Webhook", "back": "The repository host sends an event, allowing a build to begin immediately after a push."}, {"chapter": "Jenkins", "front": "Poll SCM", "back": "Jenkins checks the repository on a schedule and starts a build only when it detects changes."}, {"chapter": "Jenkins", "front": "Scheduled build", "back": "Runs the job on a schedule regardless of whether the source changed."}, {"chapter": "Jenkins", "front": "Upstream-job trigger", "back": "Starts after another Jenkins job reaches the configured result."}, {"chapter": "Jenkins", "front": "Source Code Management", "back": "Repository URL, branch, and checkout credentials."}, {"chapter": "Jenkins", "front": "Build Triggers", "back": "Manual/event/schedule conditions that start the job."}, {"chapter": "Jenkins", "front": "Build Environment", "back": "Environment preparation, credential bindings, and setup wrappers."}, {"chapter": "Jenkins", "front": "Build Steps", "back": "Shell commands, compilation, testing, and packaging."}, {"chapter": "Jenkins", "front": "Post-build Actions", "back": "Notifications, reports, archived outputs, and downstream actions."}, {"chapter": "Jenkins", "front": "pipeline", "back": "Top-level Declarative Pipeline block."}, {"chapter": "Jenkins", "front": "agent", "back": "Selects the machine or execution environment."}, {"chapter": "Jenkins", "front": "stages", "back": "Container holding one or more stage blocks."}, {"chapter": "Jenkins", "front": "stage", "back": "Names a meaningful workflow phase such as Checkout, Test, or Package."}, {"chapter": "Jenkins", "front": "steps", "back": "Execution block containing the commands and Pipeline operations for a stage."}, {"chapter": "Jenkins", "front": "Individual step", "back": "An operation such as checkout, sh, bat, echo, or archiveArtifacts."}, {"chapter": "Jenkins", "front": "post", "back": "Result-dependent actions that run after a stage or the whole Pipeline."}, {"chapter": "Jenkins", "front": "always", "back": "Run after every result."}, {"chapter": "Jenkins", "front": "success", "back": "Run only after success."}, {"chapter": "Jenkins", "front": "failure", "back": "Run only after failure."}, {"chapter": "Jenkins", "front": "changed", "back": "Run when the result changed compared with the previous completed build."}, {"chapter": "Jenkins", "front": "unstable", "back": "Run when the build is unstable."}, {"chapter": "Jenkins", "front": "cleanup", "back": "Run during final cleanup after other post conditions."}, {"chapter": "Solution Methods", "front": "Container writable layer", "back": "Private to one container and normally removed with that container."}, {"chapter": "Solution Methods", "front": "Named volume persistence", "back": "The volume exists independently of the container and normally survives container removal until explicitly deleted."}, {"chapter": "Solution Methods", "front": "Bind mount persistence", "back": "The data exists at the chosen host path and remains after container removal."}, {"chapter": "Solution Methods", "front": "Source-code suitability", "back": "Bind mounts are useful when the host must edit and immediately expose source code."}, {"chapter": "Solution Methods", "front": "Database-data suitability", "back": "Named volumes are normally preferred because Docker manages the persistent location."}, {"chapter": "Solution Methods", "front": "S3", "back": "Object storage accessed through bucket/key and APIs. Designed for extremely high object durability."}, {"chapter": "Solution Methods", "front": "EBS", "back": "Block storage attached as a disk to EC2. Use snapshots/backups for additional recovery; the volume is tied to an Availability Zone."}, {"chapter": "Solution Methods", "front": "EFS", "back": "Managed shared network filesystem that multiple instances can mount."}, {"chapter": "Solution Methods", "front": "Access pattern", "back": "Object requests -> S3; disk/block reads and writes -> EBS; shared filesystem operations -> EFS."}, {"chapter": "Solution Methods", "front": "Attachment", "back": "When storage must be attached as a disk to one EC2 instance, select EBS."}, {"chapter": "Solution Methods", "front": "Durability decision", "back": "Consider service durability plus snapshots, backups, multi-AZ/regional design, and recovery requirements."}, {"chapter": "Solution Methods", "front": "Provider plugin", "back": "The integration executable that communicates with an external platform."}, {"chapter": "Solution Methods", "front": "Required-provider declaration", "back": "Specifies source and acceptable version."}, {"chapter": "Solution Methods", "front": "Provider configuration", "back": "Sets region, endpoint, alias, and platform options."}, {"chapter": "Solution Methods", "front": "Installation", "back": "terraform init downloads the provider and records its selected version/checksum in .terraform.lock.hcl."}, {"chapter": "Solution Methods", "front": "Authentication", "back": "The provider obtains credentials through supported environment, files, roles, or platform-specific mechanisms."}, {"chapter": "Solution Methods", "front": "API translation", "back": "The provider converts Terraform create/read/update/delete plans into authenticated platform API operations and returns resulting state."}, {"chapter": "Solution Methods", "front": "Resource", "back": "A managed object whose lifecycle Terraform controls."}, {"chapter": "Solution Methods", "front": "Data source", "back": "An existing object or value Terraform reads without managing creation."}, {"chapter": "Solution Methods", "front": "Repository URL, branch, checkout credential", "back": "Source Code Management."}, {"chapter": "Solution Methods", "front": "Webhook, Poll SCM, schedule, upstream condition", "back": "Build Triggers."}, {"chapter": "Solution Methods", "front": "Credential binding, environment setup, wrappers", "back": "Build Environment."}, {"chapter": "Solution Methods", "front": "Shell commands, compile, test, package, docker build", "back": "Build Steps."}, {"chapter": "Solution Methods", "front": "Reports, artifacts, notifications, downstream action", "back": "Post-build Actions."}, {"chapter": "Solution Methods", "front": "Cleanup in Freestyle", "back": "Use an available Build Environment wrapper when cleanup surrounds execution, or an appropriate Post-build Action/plugin. In Pipeline, use post always/cleanup."}, {"chapter": "Rapid Reference", "front": "git status", "back": "Overall working-tree and staging status."}, {"chapter": "Rapid Reference", "front": "git diff", "back": "Unstaged changes."}, {"chapter": "Rapid Reference", "front": "git diff --staged", "back": "Staged changes."}, {"chapter": "Rapid Reference", "front": "git add .", "back": "Stage current-directory changes."}, {"chapter": "Rapid Reference", "front": "git commit -m \"message\"", "back": "Commit the staged snapshot."}, {"chapter": "Rapid Reference", "front": "git branch / git switch", "back": "List branches / change branches."}, {"chapter": "Rapid Reference", "front": "git merge branch", "back": "Merge branch into the current branch."}, {"chapter": "Rapid Reference", "front": "git merge --abort", "back": "Cancel an unfinished merge."}, {"chapter": "Rapid Reference", "front": "git status --ignored", "back": "Show ignored files."}, {"chapter": "Rapid Reference", "front": "git check-ignore -v file", "back": "Show the matching ignore rule."}, {"chapter": "Rapid Reference", "front": "git config --list --show-origin", "back": "Show settings and their source files."}, {"chapter": "Docker", "front": "docker images", "back": "List local images."}, {"chapter": "Docker", "front": "docker ps / docker ps -a", "back": "Running containers / all containers."}, {"chapter": "Docker", "front": "docker run -it IMAGE sh", "back": "Interactive terminal when sh exists."}, {"chapter": "Docker", "front": "docker run -p 8080:80 IMAGE", "back": "Publish host port 8080 to container port 80."}, {"chapter": "Docker", "front": "docker run --entrypoint EXE IMAGE", "back": "Replace ENTRYPOINT."}, {"chapter": "Docker", "front": "docker volume create NAME", "back": "Create a named volume."}, {"chapter": "Docker", "front": "docker network create NAME", "back": "Create a user-defined network."}, {"chapter": "Linux", "front": "echo \"$NAME\"", "back": "Display a variable."}, {"chapter": "Linux", "front": "export NAME=value", "back": "Export a variable to child processes."}, {"chapter": "Linux", "front": "command -v name", "back": "Show what the shell would run."}, {"chapter": "Linux", "front": "cmd > out 2> err", "back": "Separate normal output and errors."}, {"chapter": "Linux", "front": "cmd > all 2>&1", "back": "Send both streams to one file."}, {"chapter": "Linux", "front": "pwd -L / pwd -P", "back": "Logical path / physical path."}, {"chapter": "Linux", "front": "cd ~ / cd .. / cd -", "back": "Home / parent / previous directory."}, {"chapter": "Terraform", "front": "terraform init", "back": "Initialize."}, {"chapter": "Terraform", "front": "terraform fmt", "back": "Format."}, {"chapter": "Terraform", "front": "terraform validate", "back": "Validate."}, {"chapter": "Terraform", "front": "terraform plan", "back": "Preview."}], "source_notes": {"expanded_from": "Computing Tools Final Exam Study Guide (v2)", "coverage": "Class-covered material, professor hints, WATCH OUT distinctions, newer announcement topics, and broader review details."}};